import React, { useState, useMemo, useEffect, useRef, useCallback } from 'react';
import { Language, LexicalEntry, UserProfile } from '../types';
import { translateWord } from '../services/gemini';
import { speak, resumeAudioContext } from '../services/tts';
import { SEED_ARCHIVE } from '../constants';
import { fetchGlobalEntry, saveGlobalEntry, fetchSuggestions } from '../services/supabase';
import ResultCard from './ResultCard';
import HistoryGrid from './HistoryGrid';
import { triggerHaptic } from '../services/telegram';

interface Props {
  onEntrySaved: (entry: LexicalEntry) => void;
  autoAudio: boolean;
  setAutoAudio: (val: boolean) => void;
  profile: UserProfile;
  history: LexicalEntry[];
  onStartArena: () => void;
  selectedEntry?: LexicalEntry | null;
  onEntryClick: (entry: LexicalEntry) => void;
}

interface SuggestionItem {
  term: string;
  source: 'local' | 'global' | 'seed';
}

const LANGUAGES: Record<Language, string> = {
  German: 'GER',
  Uzbek: 'UZB',
  English: 'ENG',
  Russian: 'RUS'
};

const normalize = (text: string, lang: Language): string => {
  let res = text.trim().toLowerCase();
  if (lang === 'German') {
    res = res.replace(/ä/g, 'ae').replace(/ö/g, 'oe').replace(/ü/g, 'ue').replace(/ß/g, 'ss');
  } else if (lang === 'Russian') {
    res = res.replace(/ё/g, 'е');
  } else if (lang === 'Uzbek') {
    res = res.replace(/[‘’`]/g, "'");
  }
  return res;
};

let persistentMicStream: MediaStream | null = null;

const Dictionary: React.FC<Props> = ({ 
  onEntrySaved, 
  autoAudio, 
  setAutoAudio, 
  profile, 
  history, 
  onStartArena, 
  selectedEntry,
  onEntryClick
}) => {
  const [query, setQuery] = useState('');
  const [sourceLang, setSourceLang] = useState<Language>('German');
  const [targetLang, setTargetLang] = useState<Language>('Uzbek');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<LexicalEntry | null>(null);
  const [suggestions, setSuggestions] = useState<SuggestionItem[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [selectedIndex, setSelectedIndex] = useState(-1);
  const [isListening, setIsListening] = useState(false);

  const suggestionRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (selectedEntry) {
      setQuery(selectedEntry.term);
      setResult(selectedEntry);
      setSourceLang(selectedEntry.sourceLang);
      setTargetLang(selectedEntry.targetLang);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  }, [selectedEntry]);

  useEffect(() => {
    const delayDebounce = setTimeout(async () => {
      const trimmedQuery = query.trim().toLowerCase();
      if (trimmedQuery.length >= 2) {
        const localMatches = history
          .filter(e => e.sourceLang === sourceLang && e.term.toLowerCase().includes(trimmedQuery))
          .map(e => ({ term: e.term, source: 'local' as const }));

        const seedMatches = Object.values(SEED_ARCHIVE)
          .filter(e => e?.term && e.term.toLowerCase().includes(trimmedQuery))
          .map(e => ({ term: e!.term!, source: 'seed' as const }));

        let globalMatches: SuggestionItem[] = [];
        try {
          const globalTerms = await fetchSuggestions(query, sourceLang);
          globalMatches = globalTerms.map(term => ({ term, source: 'global' as const }));
        } catch (e) {
          console.warn("Global suggestions fetch failed");
        }

        const combined = [...localMatches, ...seedMatches, ...globalMatches];
        const unique = combined.filter((v, i, a) => 
          a.findIndex(t => t.term.toLowerCase() === v.term.toLowerCase()) === i
        ).slice(0, 8);

        setSuggestions(unique);
        setShowSuggestions(unique.length > 0);
        setSelectedIndex(-1);
      } else {
        setSuggestions([]);
        setShowSuggestions(false);
      }
    }, 250);
    return () => clearTimeout(delayDebounce);
  }, [query, sourceLang, history]);

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (suggestionRef.current && !suggestionRef.current.contains(e.target as Node)) {
        setShowSuggestions(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleSourceLangChange = useCallback(async (lang: Language) => {
    await resumeAudioContext();
    if (lang === targetLang) setTargetLang(sourceLang);
    setSourceLang(lang);
    triggerHaptic('light');
  }, [sourceLang, targetLang]);

  const handleTargetLangChange = useCallback(async (lang: Language) => {
    await resumeAudioContext();
    if (lang === sourceLang) setSourceLang(targetLang);
    setTargetLang(lang);
    triggerHaptic('light');
  }, [sourceLang, targetLang]);

  const localCache = useMemo(() => {
    const cache = new Map<string, LexicalEntry>();
    Object.entries(SEED_ARCHIVE).forEach(([key, entry]) => {
      const parts = key.split('-');
      const sL = parts[1] as Language;
      const tL = parts[2] as Language;
      if (entry.term) {
        const norm = normalize(entry.term, sL);
        cache.set(`${norm}-${sL}-${tL}`, { ...entry, id: `seed-${key}`, normalizedTerm: norm, sourceLang: sL, targetLang: tL } as any);
      }
    });
    history.forEach(entry => {
      const norm = normalize(entry.term, entry.sourceLang);
      cache.set(`${norm}-${entry.sourceLang}-${entry.targetLang}`, entry);
    });
    return cache;
  }, [history]);

  const handleSearch = async (overrideQuery?: string) => {
    const cleanQuery = (overrideQuery || query).trim();
    if (!cleanQuery) return;

    if (inputRef.current) inputRef.current.blur();

    await resumeAudioContext();
    setShowSuggestions(false);
    setQuery(cleanQuery);

    if (autoAudio) {
      speak(cleanQuery, sourceLang).catch(() => {});
    }

    const normQuery = normalize(cleanQuery, sourceLang);
    const cacheKey = `${normQuery}-${sourceLang}-${targetLang}`;

    const localHit = localCache.get(cacheKey);
    if (localHit) {
      setResult(localHit);
      if (autoAudio) {
        setTimeout(() => speak(localHit.mainTranslation, targetLang).catch(() => {}), 400);
      }
      return;
    }

    setLoading(true);
    setResult(null);

    try {
      const globalHit = await fetchGlobalEntry(normQuery, sourceLang, targetLang);
      if (globalHit) {
        setResult(globalHit);
        onEntrySaved(globalHit);
        setLoading(false);
        if (autoAudio) {
          setTimeout(() => speak(globalHit.mainTranslation, targetLang).catch(() => {}), 400);
        }
        return;
      }

      const finalEntry = await translateWord(cleanQuery, sourceLang, targetLang);
      finalEntry.normalizedTerm = normQuery;

      setResult(finalEntry);
      onEntrySaved(finalEntry);
      saveGlobalEntry(finalEntry);

      if (autoAudio) {
        setTimeout(() => speak(finalEntry.mainTranslation, targetLang).catch(() => {}), 400);
      }
    } catch (err) {
      console.error("Philologist Engine Error:", err);
      triggerHaptic('error');
    } finally {
      setLoading(false);
    }
  };

  const startVoiceSearch = async () => {
    if (isListening) return;

    if (!persistentMicStream) {
      try {
        persistentMicStream = await navigator.mediaDevices.getUserMedia({ audio: true });
      } catch (err) {
        console.warn("Linguistic access denied:", err);
      }
    }

    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      alert("Linguistic transcription not supported in this vessel.");
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.lang = sourceLang === 'German' ? 'de-DE' : sourceLang === 'Russian' ? 'ru-RU' : sourceLang === 'Uzbek' ? 'uz-UZ' : 'en-US';
    recognition.interimResults = false;
    recognition.maxAlternatives = 1;

    recognition.onstart = () => {
      setIsListening(true);
      triggerHaptic('medium');
    };

    recognition.onresult = (event: any) => {
      const speechToText = event.results[0][0].transcript;
      setQuery(speechToText);
      handleSearch(speechToText);
    };

    recognition.onerror = (event: any) => {
      setIsListening(false);
      if (event.error !== 'no-speech') triggerHaptic('error');
    };

    recognition.onend = () => setIsListening(false);

    try {
      recognition.start();
    } catch (e) {
      setIsListening(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      if (selectedIndex >= 0) {
        const selected = suggestions[selectedIndex];
        setQuery(selected.term);
        handleSearch(selected.term);
      } else {
        handleSearch();
      }
      resumeAudioContext(); 
    }
    if (!showSuggestions) return;

    if (e.key === 'ArrowDown') {
      e.preventDefault();
      setSelectedIndex(prev => (prev + 1) % suggestions.length);
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      setSelectedIndex(prev => (prev - 1 + suggestions.length) % suggestions.length);
    } else if (e.key === 'Escape') {
      setShowSuggestions(false);
    }
  };

  const swapLanguages = useCallback(async () => {
    await resumeAudioContext();
    const oldSource = sourceLang;
    const oldTarget = targetLang;
    setSourceLang(oldTarget);
    setTargetLang(oldSource);
    triggerHaptic('medium');
  }, [sourceLang, targetLang]);

  return (
    <div className="space-y-8 md:space-y-16 max-w-7xl mx-auto contain-layout">
      {/* Philological Mastery Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-8 pt-4">
        <div className="flex items-center gap-6">
          <div className="space-y-1 border-l-2 border-[#7c1a1a] pl-4 block">
            <span className="text-[8px] uppercase tracking-[0.4em] text-stone-400 font-black">Philological Mastery</span>
            <div className="flex items-baseline gap-2">
              <span className="text-xl md:text-2xl font-black serif text-stone-900 leading-none">{profile.xp}</span>
              <span className="text-[7px] uppercase tracking-[0.2em] text-stone-300 font-bold">Total XP</span>
            </div>
          </div>
        </div>

        {/* Language Selection Interface */}
        <div className="flex flex-col lg:flex-row items-center gap-6 lg:gap-12 w-full md:w-auto">
          <div className="flex flex-col sm:flex-row items-center gap-4 bg-stone-50 p-2 rounded-sm w-full sm:w-auto border border-stone-100 shadow-inner">
             <div className="grid grid-cols-4 bg-white shadow-sm overflow-hidden rounded-sm w-full sm:w-auto ring-1 ring-stone-100">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button key={`source-${full}`} type="button" onClick={() => handleSourceLangChange(full)}
                    className={`px-3 sm:px-5 py-2.5 text-[9px] font-black tracking-widest border-r border-stone-100 last:border-r-0 transition-all ${sourceLang === full ? 'bg-stone-900 text-white' : 'text-stone-300 hover:text-stone-600'}`}>
                    {short}
                  </button>
                ))}
             </div>
             <button type="button" onClick={swapLanguages} className="text-stone-300 hover:text-[#7c1a1a] p-2 hover:bg-white rounded-full transition-all shadow-sm active:scale-90">
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M7 16V4M7 4L3 8M7 4L11 8M17 8V20M17 20L21 16M17 20L13 16"/></svg>
             </button>
             <div className="grid grid-cols-4 bg-white shadow-sm overflow-hidden rounded-sm w-full sm:w-auto ring-1 ring-stone-100">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button key={`target-${full}`} type="button" onClick={() => handleTargetLangChange(full)}
                    className={`px-3 sm:px-5 py-2.5 text-[9px] font-black tracking-widest border-r border-stone-100 last:border-r-0 transition-all ${targetLang === full ? 'bg-[#7c1a1a] text-white' : 'text-stone-300 hover:text-stone-600'}`}>
                    {short}
                  </button>
                ))}
             </div>
          </div>
        </div>
      </div>

      {/* Main Search Input Container */}
      <div className="relative group max-w-4xl mx-auto w-full">
        <div className={`relative flex items-center transition-all duration-500 rounded-sm overflow-hidden border-2 ${loading ? 'border-[#7c1a1a]/30 shadow-2xl' : 'border-stone-900 shadow-xl'}`}>
          <div className="absolute left-6 text-stone-300">
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
          </div>

          <input
            ref={inputRef}
            type="text"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="Summon inscription for analysis..."
            className="w-full pl-16 pr-48 py-8 md:py-10 text-2xl md:text-5xl serif bg-white text-stone-900 placeholder:text-stone-200 focus:outline-none lowercase tracking-tighter"
          />

          <div className="absolute right-6 flex items-center gap-3 md:gap-4">
             <button 
                onClick={startVoiceSearch}
                className={`p-3 rounded-full transition-all ${isListening ? 'bg-[#7c1a1a] text-white animate-pulse' : 'bg-stone-50 text-stone-300 hover:text-stone-900 shadow-sm'}`}
             >
                <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2a3 3 0 0 0-3 3v7a3 3 0 0 0 6 0V5a3 3 0 0 0-3-3Z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" x2="12" y1="19" y2="22"/></svg>
             </button>
             <button 
                onClick={() => handleSearch()}
                disabled={loading}
                className={`hidden md:block px-8 py-3 bg-stone-900 text-white text-[10px] font-black uppercase tracking-[0.4em] transition-all hover:bg-stone-800 ${loading ? 'opacity-50' : 'active:scale-95'}`}
             >
                {loading ? 'Consulting...' : 'Search'}
             </button>
          </div>
        </div>

        {/* Suggestions Portal */}
        {showSuggestions && (
          <div ref={suggestionRef} className="absolute top-full left-0 right-0 mt-1 bg-white border-2 border-stone-900 z-50 shadow-2xl animate-in fade-in slide-in-from-top-2 duration-200">
            {suggestions.map((s, idx) => (
              <div 
                key={idx}
                onClick={() => { setQuery(s.term); handleSearch(s.term); }}
                onMouseEnter={() => setSelectedIndex(idx)}
                className={`px-8 py-4 flex items-center justify-between cursor-pointer border-b border-stone-100 last:border-b-0 transition-colors ${selectedIndex === idx ? 'bg-stone-50' : ''}`}
              >
                <span className="text-xl serif text-stone-900 lowercase">{s.term}</span>
                <span className="text-[8px] uppercase tracking-widest font-black text-stone-300">{s.source}</span>
              </div>
            ))}
          </div>
        )}

        <div className="mt-6 flex items-center justify-between">
           <div className="flex items-center gap-6">
              <label className="flex items-center gap-3 cursor-pointer group">
                <input type="checkbox" checked={autoAudio} onChange={e => setAutoAudio(e.target.checked)} className="hidden" />
                <div className={`w-8 h-4 rounded-full relative transition-all duration-300 ${autoAudio ? 'bg-[#7c1a1a]' : 'bg-stone-200'}`}>
                  <div className={`absolute top-0.5 w-3 h-3 rounded-full bg-white transition-all duration-300 ${autoAudio ? 'left-4.5' : 'left-0.5'}`} />
                </div>
                <span className="text-[9px] uppercase tracking-widest text-stone-400 font-bold group-hover:text-stone-600 transition-colors">Lexical Voicing</span>
              </label>
           </div>

           <button onClick={onStartArena} className="text-[9px] uppercase tracking-widest text-[#7c1a1a] font-black hover:underline underline-offset-4 decoration-2">
             Begin Scholarly Trial
           </button>
        </div>
      </div>

      {/* Search Result Display */}
      {loading && (
        <div className="py-32 flex flex-col items-center justify-center space-y-8">
           <div className="relative w-24 h-24">
              <div className="absolute inset-0 border-[3px] border-stone-100 rounded-full"></div>
              <div className="absolute inset-0 border-[3px] border-[#7c1a1a] border-t-transparent rounded-full animate-spin"></div>
              <div className="absolute inset-4 border-[1px] border-stone-100 rounded-full animate-pulse"></div>
           </div>
           <p className="serif text-2xl italic text-stone-300 lowercase animate-pulse">Consulting the digital archive...</p>
        </div>
      )}

      {result && <ResultCard entry={result} onSearchTerm={handleSearch} />}

      {/* Initial Landing or No Result: Scholarly Insights */}
      {!result && !loading && (
        <div className="space-y-16 py-12">
          <section>
             <h2 className="text-[10px] uppercase tracking-[0.5em] text-stone-300 font-black mb-12 text-center">Recent Historical Inscriptions</h2>
             {history.length > 0 ? (
               <HistoryGrid history={history.slice(0, 6)} onEntryClick={onEntryClick} />
             ) : (
               <div className="text-center py-20 border border-stone-100 bg-stone-50/30 rounded-sm">
                  <p className="serif text-3xl italic text-stone-200 lowercase">The archive awaits your first inquiry.</p>
               </div>
             )}
          </section>

          <section className="max-w-3xl mx-auto bg-stone-900 text-white p-12 md:p-20 relative overflow-hidden shadow-2xl rounded-sm">
             <div className="absolute -top-10 -right-10 text-[180px] serif font-black text-white/5 pointer-events-none">LEX.</div>
             <div className="relative z-10">
                <span className="text-[10px] uppercase tracking-[0.4em] text-[#7c1a1a] font-black block mb-6">Lexical Insight</span>
                <h3 className="text-4xl md:text-6xl serif font-black leading-tight mb-8">Language is the architecture of memory.</h3>
                <p className="text-stone-400 serif italic text-xl md:text-2xl leading-relaxed mb-10">
                  UzGer Lexicon is not merely a translator, but a philological vessel designed to capture the nuance, etymology, and cultural resonance of every word.
                </p>
                <div className="h-[1px] w-24 bg-[#7c1a1a] mb-10"></div>
                <div className="flex flex-wrap gap-8 text-[9px] uppercase tracking-[0.3em] font-black">
                   <div className="flex flex-col gap-1">
                      <span className="text-white">4 Languages</span>
                      <span className="text-stone-500">Supported</span>
                   </div>
                   <div className="flex flex-col gap-1">
                      <span className="text-white">CEFR Mapping</span>
                      <span className="text-stone-500">Integrated</span>
                   </div>
                   <div className="flex flex-col gap-1">
                      <span className="text-white">Philology</span>
                      <span className="text-stone-500">First</span>
                   </div>
                </div>
             </div>
          </section>
        </div>
      )}
    </div>
  );
};

export default Dictionary;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { AppMode, LexicalEntry, UserProfile } from './types';
import Dictionary from './components/Dictionary';
import Arena from './components/Arena';
import Archive from './components/Archive';
import { RANKS } from './constants';
import { 
  fetchProfile, 
  upsertProfile, 
  fetchUserHistory, 
  saveUserHistoryEntry 
} from './services/supabase';
import { 
  getTelegramUser,
  initTelegramTheme, 
  isTelegramEnvironment,
  openTelegramLink,
  triggerHaptic
} from './services/telegram';
import { resumeAudioContext } from './services/tts';

const App: React.FC = () => {
  const [mode, setMode] = useState<AppMode>(AppMode.DICTIONARY);
  const [history, setHistory] = useState<LexicalEntry[]>([]);
  const [activeEntry, setActiveEntry] = useState<LexicalEntry | null>(null);
  const [autoAudio, setAutoAudio] = useState(() => localStorage.getItem('autoAudio') === 'true');
  const [isSyncing, setIsSyncing] = useState(false);
  const [cloudActive, setCloudActive] = useState(false);

  const initialHydrationRef = useRef(false);

  const [profile, setProfile] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('lexProfile');
    return saved ? JSON.parse(saved) : {
      username: 'Scholar',
      xp: 0,
      rank: RANKS[0].title,
      searchCount: 0,
      arenaWins: 0,
      accuracy: 100,
      streak: 0
    };
  });

  useEffect(() => {
    const handleFirstInteraction = async () => {
      await resumeAudioContext();
      document.removeEventListener('touchstart', handleFirstInteraction);
      document.removeEventListener('mousedown', handleFirstInteraction);
    };
    document.addEventListener('touchstart', handleFirstInteraction);
    document.addEventListener('mousedown', handleFirstInteraction);
    return () => {
      document.removeEventListener('touchstart', handleFirstInteraction);
      document.removeEventListener('mousedown', handleFirstInteraction);
    };
  }, []);

  const syncProfileToCloud = useCallback(async (newProfile: UserProfile) => {
    if (!newProfile.telegramId) return;
    setIsSyncing(true);
    try {
      await upsertProfile(newProfile);
      setCloudActive(true);
    } catch (err) {
      console.error("Cloud Archive Sync Failed:", err);
      setCloudActive(false);
    } finally {
      setIsSyncing(false);
    }
  }, []);

  useEffect(() => {
    if (initialHydrationRef.current) return;
    initialHydrationRef.current = true;

    const performHydration = async () => {
      const savedHistory = localStorage.getItem('lexHistory');
      if (savedHistory) setHistory(JSON.parse(savedHistory));

      const tgUser = isTelegramEnvironment() ? getTelegramUser() : null;
      if (tgUser) {
        initTelegramTheme();
        setIsSyncing(true);
        try {
          const [cloudProf, cloudHist] = await Promise.all([
            fetchProfile(tgUser.id),
            fetchUserHistory(tgUser.id)
          ]);

          let finalProfile: UserProfile;

          if (cloudProf) {
            finalProfile = {
              ...cloudProf,
              username: tgUser.username || cloudProf.username,
              firstName: tgUser.first_name || cloudProf.firstName,
              lastName: tgUser.last_name || cloudProf.lastName,
              languageCode: tgUser.language_code || cloudProf.languageCode,
              telegramId: tgUser.id
            };
            setCloudActive(true);
          } else {
            finalProfile = {
              username: tgUser.username || 'Scholar',
              firstName: tgUser.first_name || '',
              lastName: tgUser.last_name || '',
              telegramId: tgUser.id,
              languageCode: tgUser.language_code || 'en',
              xp: profile.xp,
              rank: profile.rank,
              searchCount: profile.searchCount,
              arenaWins: profile.arenaWins,
              accuracy: profile.accuracy,
              streak: profile.streak
            };
          }

          setProfile(finalProfile);
          await upsertProfile(finalProfile);
          setCloudActive(true);

          if (cloudHist && cloudHist.length > 0) {
            setHistory(prev => {
              const combined = [...cloudHist, ...prev];
              const uniqueMap = new Map();
              combined.forEach(item => {
                const key = `${item.term}-${item.sourceLang}-${item.targetLang}`;
                if (!uniqueMap.has(key)) uniqueMap.set(key, item);
              });
              return Array.from(uniqueMap.values()).slice(0, 50);
            });
          }
        } catch (err) {
          console.error("Archival connection failure:", err);
          setCloudActive(false);
        } finally {
          setIsSyncing(false);
        }
      }
    };

    performHydration();
  }, []);

  useEffect(() => {
    localStorage.setItem('lexHistory', JSON.stringify(history));
  }, [history]);

  useEffect(() => {
    localStorage.setItem('lexProfile', JSON.stringify(profile));
    if (profile.telegramId) {
      syncProfileToCloud(profile);
    }
  }, [profile, syncProfileToCloud]);

  useEffect(() => {
    localStorage.setItem('autoAudio', String(autoAudio));
  }, [autoAudio]);

  const addEntry = async (entry: LexicalEntry) => {
    setHistory(prev => {
      const filtered = prev.filter(p => p.term.toLowerCase() !== entry.term.toLowerCase());
      return [entry, ...filtered].slice(0, 50);
    });

    const newXp = profile.xp + 2;
    const newRank = RANKS.reduce((prev, curr) => newXp >= curr.minXp ? curr : prev, RANKS[0]);
    const newProfile = { 
      ...profile, 
      xp: newXp, 
      rank: newRank.title,
      searchCount: profile.searchCount + 1 
    };

    setProfile(newProfile);

    if (newProfile.telegramId) {
      try {
        await saveUserHistoryEntry(newProfile.telegramId, entry);
      } catch (err) {
        console.warn("Cloud persistence failed.");
      }
    }
  };

  const handleArenaResult = (correctCount: number, totalQuestions: number) => {
    const earnedXp = correctCount * 5;
    const sessionAccuracy = totalQuestions > 0 ? (correctCount / totalQuestions) * 100 : 0;

    const newXp = profile.xp + earnedXp;
    const newRank = RANKS.reduce((prev, curr) => newXp >= curr.minXp ? curr : prev, RANKS[0]);
    const newAccuracy = profile.accuracy === 100 ? sessionAccuracy : (profile.accuracy + sessionAccuracy) / 2;

    const newProfile = { 
      ...profile, 
      xp: newXp, 
      rank: newRank.title,
      arenaWins: profile.arenaWins + 1,
      accuracy: Math.round(newAccuracy),
      streak: correctCount === totalQuestions ? profile.streak + 1 : 0
    };

    setProfile(newProfile);
  };

  const handleHistoryItemClick = (entry: LexicalEntry) => {
    setActiveEntry(entry);
    setMode(AppMode.DICTIONARY);
  };

  return (
    <div className="min-h-screen bg-[#fcfcfb] flex flex-col selection:bg-[#7c1a1a]/10 selection:text-[#7c1a1a]">
      <header className="px-6 md:px-12 pt-8 pb-4 pt-safe max-w-[1400px] mx-auto w-full">
        <div className="flex items-center gap-6 mb-8">
          <span 
            onClick={() => { setActiveEntry(null); setMode(AppMode.DICTIONARY); triggerHaptic('light'); }}
            className="text-3xl md:text-4xl serif font-black tracking-tighter cursor-pointer text-[#7c1a1a]"
          >
            LEX.
          </span>
          <div className="flex flex-col">
            <span className="text-[10px] uppercase tracking-[0.4em] text-stone-900 font-black leading-none mb-1">
              Polyglot Insight Engine
            </span>
            <span className="text-[8px] uppercase tracking-[0.2em] text-stone-300 font-bold">
              Archival Philology
            </span>
          </div>
        </div>

        <nav className="flex items-center gap-8 text-[10px] uppercase tracking-[0.2em] font-black text-stone-400 border-b border-stone-100">
          <button 
            onClick={() => { setActiveEntry(null); setMode(AppMode.DICTIONARY); triggerHaptic('light'); }} 
            className={`pb-3 transition-all border-b-2 ${mode === AppMode.DICTIONARY ? 'border-[#7c1a1a] text-stone-900' : 'border-transparent'}`}
          >
            Encyclopedia
          </button>
          <button 
            onClick={() => { setMode(AppMode.ARENA); triggerHaptic('light'); }} 
            className={`pb-3 transition-all border-b-2 ${mode === AppMode.ARENA ? 'border-[#7c1a1a] text-stone-900' : 'border-transparent'}`}
          >
            Arena
          </button>
          <button 
            onClick={() => { setMode(AppMode.ARCHIVE); triggerHaptic('light'); }} 
            className={`pb-3 transition-all border-b-2 ${mode === AppMode.ARCHIVE ? 'border-[#7c1a1a] text-stone-900' : 'border-transparent'}`}
          >
            Chronicles
          </button>
          <button 
            onClick={() => openTelegramLink('https://t.me/lex_uz_support')} 
            className="pb-3 border-b-2 border-transparent flex items-center gap-1"
          >
            Support <svg xmlns="http://www.w3.org/2000/svg" width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M15 3h6v6"/><path d="M10 14L21 3"/><path d="M18 13v6a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h6"/></svg>
          </button>
        </nav>
      </header>

      <main className="flex-1">
        <div className="max-w-[1400px] mx-auto px-6 md:px-12 pb-20">
          {mode === AppMode.DICTIONARY && (
            <Dictionary 
              onEntrySaved={addEntry} 
              autoAudio={autoAudio} 
              setAutoAudio={setAutoAudio}
              profile={profile}
              history={history}
              onStartArena={() => setMode(AppMode.ARENA)}
              selectedEntry={activeEntry}
              onEntryClick={handleHistoryItemClick}
            />
          )}

          {mode === AppMode.ARENA && (
            <Arena history={history} onResult={handleArenaResult} />
          )}

          {mode === AppMode.ARCHIVE && (
            <Archive history={history} onEntryClick={handleHistoryItemClick} />
          )}
        </div>
      </main>

      <footer className="py-8 border-t border-stone-100 bg-white/50 pb-safe">
        <div className="max-w-[1400px] mx-auto px-6 md:px-12 flex flex-col md:flex-row justify-between items-center gap-4 text-[9px] uppercase tracking-[0.3em] text-stone-400 font-black">
          <div className="flex items-center gap-6">
             <span>&copy; 2025 LEXICON PHILOLOGY</span>
             <span className={`flex items-center gap-2 ${isSyncing ? 'text-[#7c1a1a] animate-pulse' : ''}`}>
               <span className={`w-2 h-2 rounded-full ${isSyncing ? 'bg-[#7c1a1a]' : cloudActive ? 'bg-green-500' : 'bg-stone-200'}`} />
               {isSyncing ? 'Syncing...' : cloudActive ? 'Cloud Active' : 'Offline'}
             </span>
