export default App;

import React, { useState, useMemo, useEffect, useRef, useCallback } from 'react';
import { Language, LexicalEntry, UserProfile } from '../types';
import { translateWord } from '../services/gemini';
import { speak, resumeAudioContext } from '../services/tts';
import { SEED_ARCHIVE } from '../constants';
import { fetchGlobalEntry, saveGlobalEntry, fetchSuggestions } from '../services/supabase';
import ResultCard from './ResultCard';
import HistoryGrid from './HistoryGrid';
import { triggerHaptic } from '../services/telegram';

interface Props {
  onEntrySaved: (entry: LexicalEntry) => void;
  autoAudio: boolean;
  setAutoAudio: (val: boolean) => void;
  profile: UserProfile;
  history: LexicalEntry[];
  onStartArena: () => void;
  selectedEntry?: LexicalEntry | null;
  onEntryClick: (entry: LexicalEntry) => void;
}

interface SuggestionItem {
  term: string;
  source: 'local' | 'global' | 'seed';
}

const LANGUAGES: Record<Language, string> = {
  German: 'GER',
  Uzbek: 'UZB',
  English: 'ENG',
  Russian: 'RUS'
};

const normalize = (text: string, lang: Language): string => {
  let res = text.trim().toLowerCase();
  if (lang === 'German') {
    res = res.replace(/ä/g, 'ae').replace(/ö/g, 'oe').replace(/ü/g, 'ue').replace(/ß/g, 'ss');
  } else if (lang === 'Russian') {
    res = res.replace(/ё/g, 'е');
  } else if (lang === 'Uzbek') {
    res = res.replace(/[‘’`]/g, "'");
  }
  return res;
};

let persistentMicStream: MediaStream | null = null;

const Dictionary: React.FC<Props> = ({ 
  onEntrySaved, 
  autoAudio, 
  setAutoAudio, 
  profile, 
  history, 
  onStartArena, 
  selectedEntry,
  onEntryClick
}) => {
  const [query, setQuery] = useState('');
  const [sourceLang, setSourceLang] = useState<Language>('German');
  const [targetLang, setTargetLang] = useState<Language>('Uzbek');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<LexicalEntry | null>(null);
  const [suggestions, setSuggestions] = useState<SuggestionItem[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [selectedIndex, setSelectedIndex] = useState(-1);
  const [isListening, setIsListening] = useState(false);

  const suggestionRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (selectedEntry) {
      setQuery(selectedEntry.term);
      setResult(selectedEntry);
      setSourceLang(selectedEntry.sourceLang);
      setTargetLang(selectedEntry.targetLang);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  }, [selectedEntry]);

  useEffect(() => {
    const delayDebounce = setTimeout(async () => {
      const trimmedQuery = query.trim().toLowerCase();
      if (trimmedQuery.length >= 2) {
        const localMatches = history
          .filter(e => e.sourceLang === sourceLang && e.term.toLowerCase().includes(trimmedQuery))
          .map(e => ({ term: e.term, source: 'local' as const }));

        const seedMatches = Object.values(SEED_ARCHIVE)
          .filter(e => e?.term && e.term.toLowerCase().includes(trimmedQuery))
          .map(e => ({ term: e!.term!, source: 'seed' as const }));

        let globalMatches: SuggestionItem[] = [];
        try {
          const globalTerms = await fetchSuggestions(query, sourceLang);
          globalMatches = globalTerms.map(term => ({ term, source: 'global' as const }));
        } catch (e) {
          console.warn("Global suggestions fetch failed");
        }

        const combined = [...localMatches, ...seedMatches, ...globalMatches];
        const unique = combined.filter((v, i, a) => 
          a.findIndex(t => t.term.toLowerCase() === v.term.toLowerCase()) === i
        ).slice(0, 8);

        setSuggestions(unique);
        setShowSuggestions(unique.length > 0);
        setSelectedIndex(-1);
      } else {
        setSuggestions([]);
        setShowSuggestions(false);
      }
    }, 250);
    return () => clearTimeout(delayDebounce);
  }, [query, sourceLang, history]);

  const handleSourceLangChange = useCallback(async (lang: Language) => {
    await resumeAudioContext();
    if (lang === targetLang) setTargetLang(sourceLang);
    setSourceLang(lang);
    triggerHaptic('light');
  }, [sourceLang, targetLang]);

  const handleTargetLangChange = useCallback(async (lang: Language) => {
    await resumeAudioContext();
    if (lang === sourceLang) setSourceLang(targetLang);
    setTargetLang(lang);
    triggerHaptic('light');
  }, [sourceLang, targetLang]);

  const handleSearch = async (overrideQuery?: string) => {
    const cleanQuery = (overrideQuery || query).trim();
    if (!cleanQuery) return;

    if (inputRef.current) inputRef.current.blur();

    await resumeAudioContext();
    setShowSuggestions(false);
    setQuery(cleanQuery);

    if (autoAudio) {
      speak(cleanQuery, sourceLang).catch(() => {});
    }

    const normQuery = normalize(cleanQuery, sourceLang);
    setLoading(true);
    setResult(null);

    try {
      const globalHit = await fetchGlobalEntry(normQuery, sourceLang, targetLang);
      if (globalHit) {
        setResult(globalHit);
        onEntrySaved(globalHit);
        setLoading(false);
        if (autoAudio) {
          setTimeout(() => speak(globalHit.mainTranslation, targetLang).catch(() => {}), 400);
        }
        return;
      }

      const finalEntry = await translateWord(cleanQuery, sourceLang, targetLang);
      finalEntry.normalizedTerm = normQuery;
      setResult(finalEntry);
      onEntrySaved(finalEntry);
      saveGlobalEntry(finalEntry);
      if (autoAudio) {
        setTimeout(() => speak(finalEntry.mainTranslation, targetLang).catch(() => {}), 400);
      }
    } catch (err) {
      console.error("Engine Error:", err);
      triggerHaptic('error');
    } finally {
      setLoading(false);
    }
  };

  const startVoiceSearch = async () => {
    if (isListening) return;
    if (!persistentMicStream) {
      try {
        persistentMicStream = await navigator.mediaDevices.getUserMedia({ audio: true });
      } catch (err) { console.warn("Mic access denied"); }
    }
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) return;

    const recognition = new SpeechRecognition();
    recognition.lang = sourceLang === 'German' ? 'de-DE' : sourceLang === 'Russian' ? 'ru-RU' : sourceLang === 'Uzbek' ? 'uz-UZ' : 'en-US';
    recognition.onstart = () => { setIsListening(true); triggerHaptic('medium'); };
    recognition.onresult = (event: any) => {
      const speechToText = event.results[0][0].transcript;
      setQuery(speechToText);
      handleSearch(speechToText);
    };
    recognition.onerror = () => setIsListening(false);
    recognition.onend = () => setIsListening(false);
    try { recognition.start(); } catch { setIsListening(false); }
  };

  const swapLanguages = useCallback(async () => {
    await resumeAudioContext();
    const oldSource = sourceLang;
    const oldTarget = targetLang;
    setSourceLang(oldTarget);
    setTargetLang(oldSource);
    triggerHaptic('medium');
  }, [sourceLang, targetLang]);

  return (
    <div className="space-y-12 max-w-4xl mx-auto">
      {/* Philological Mastery Block */}
      <div className="pt-4">
        <div className="border-l-2 border-[#7c1a1a] pl-4">
          <span className="text-[10px] uppercase tracking-[0.4em] text-stone-300 font-bold block mb-1">Philological Mastery</span>
          <div className="flex items-baseline gap-2">
            <span className="text-2xl font-black serif text-stone-900">{profile.xp}</span>
            <span className="text-[8px] uppercase tracking-[0.2em] text-stone-300 font-bold">Total XP</span>
          </div>
        </div>
      </div>

      {/* Language Selection Grid */}
      <div className="flex flex-col items-center gap-2">
         <div className="grid grid-cols-4 bg-stone-900 rounded-sm overflow-hidden w-full max-w-sm">
            {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
              <button key={`src-${full}`} onClick={() => handleSourceLangChange(full)}
                className={`py-2 text-[10px] font-black tracking-widest transition-all ${sourceLang === full ? 'bg-stone-900 text-white' : 'bg-white text-stone-300'}`}>
                {short}
              </button>
            ))}
         </div>
         <button onClick={swapLanguages} className="text-stone-300 p-1">
            <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M7 16V4M7 4L3 8M7 4L11 8M17 8V20M17 20L21 16M17 20L13 16"/></svg>
         </button>
         <div className="grid grid-cols-4 bg-[#7c1a1a] rounded-sm overflow-hidden w-full max-w-sm">
            {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
              <button key={`trg-${full}`} onClick={() => handleTargetLangChange(full)}
                className={`py-2 text-[10px] font-black tracking-widest transition-all ${targetLang === full ? 'bg-[#7c1a1a] text-white' : 'bg-white text-stone-300'}`}>
                {short}
              </button>
            ))}
         </div>
      </div>

      <div className="flex justify-center">
        <label className="flex items-center gap-3 cursor-pointer">
          <span className="text-[10px] uppercase tracking-widest text-stone-400 font-bold">Auto-Pronounce</span>
          <div className={`w-10 h-5 rounded-full relative transition-all ${autoAudio ? 'bg-[#7c1a1a]' : 'bg-stone-200'}`}>
            <input type="checkbox" checked={autoAudio} onChange={e => setAutoAudio(e.target.checked)} className="sr-only" />
            <div className={`absolute top-1 w-3 h-3 rounded-full bg-white transition-all ${autoAudio ? 'left-6' : 'left-1'}`} />
          </div>
        </label>
      </div>

      {/* Main Search Bar */}
      <div className="relative">
        <div className="flex items-center border border-stone-100 bg-stone-50/30 rounded-sm overflow-hidden shadow-sm">
          <input
            ref={inputRef}
            type="text"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSearch()}
            placeholder="summon an inscriptio..."
            className="w-full pl-8 py-5 text-xl serif bg-transparent text-stone-900 placeholder:text-stone-200 focus:outline-none italic"
          />
          <button onClick={startVoiceSearch} className={`px-6 text-stone-300 transition-colors ${isListening ? 'text-[#7c1a1a]' : ''}`}>
            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M12 2a3 3 0 0 0-3 3v7a3 3 0 0 0 6 0V5a3 3 0 0 0-3-3Z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" x2="12" y1="19" y2="22"/></svg>
          </button>
          <button onClick={() => handleSearch()} className="px-8 py-5 bg-stone-50/50 border-l border-stone-100 text-stone-400 hover:text-stone-900 transition-colors">
            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M5 12h14"/><path d="m12 5 7 7-7 7"/></svg>
          </button>
        </div>
      </div>

      {/* Discovery Section */}
      {!result && !loading && (
        <div className="text-center space-y-4 py-12">
           <h2 className="text-4xl font-black serif text-stone-900 lowercase tracking-tight">scholarly discovery</h2>
           <p className="text-stone-300 serif italic text-xl max-w-lg mx-auto leading-relaxed">
             The engine awaits your command. Search for etymologies, or test your mastery in the <span className="text-[#7c1a1a] underline underline-offset-4 decoration-1 cursor-pointer" onClick={onStartArena}>Scholarly Arena</span>.
           </p>
        </div>
      )}

      {loading && (
        <div className="flex flex-col items-center py-20 animate-pulse">
          <div className="w-10 h-10 border-2 border-[#7c1a1a] border-t-transparent rounded-full animate-spin mb-4" />
          <span className="text-[10px] uppercase tracking-[0.3em] text-stone-300 font-bold">Consulting Archives</span>
        </div>
      )}

      {result && <ResultCard entry={result} onSearchTerm={handleSearch} />}

      {/* Archival Chronicles */}
      {!result && !loading && (
        <div className="space-y-8 pt-12">
          <div className="border-l-2 border-[#7c1a1a] pl-4">
             <h2 className="text-[10px] uppercase tracking-[0.4em] text-stone-900 font-black">Archival Chronicles</h2>
             <span className="text-[8px] uppercase tracking-[0.2em] text-stone-300 font-bold">Persistent Insights</span>
          </div>

          <button onClick={onStartArena} className="w-full bg-[#7c1a1a] text-white py-4 flex items-center justify-center gap-3 text-[10px] font-black uppercase tracking-[0.3em] shadow-lg rounded-sm active:scale-95 transition-transform">
             <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="currentColor"><path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z"/></svg>
             Start Arena
          </button>

          <HistoryGrid history={history.slice(0, 12)} onEntryClick={onEntryClick} />
        </div>
      )}
    </div>
  );
};

