import React, { useState, useEffect, useCallback, useRef } from 'react';
import { AppMode, LexicalEntry, UserProfile } from './types';
import Dictionary from './components/Dictionary';
import Arena from './components/Arena';
import Archive from './components/Archive';
import { RANKS } from './constants';
import { 
  fetchProfile, 
  upsertProfile, 
  fetchUserHistory, 
  saveUserHistoryEntry 
} from './services/supabase';
import { 
  getTelegramUser,
  initTelegramTheme, 
  isTelegramEnvironment,
  openTelegramLink,
  triggerHaptic
} from './services/telegram';
import { resumeAudioContext } from './services/tts';

const App: React.FC = () => {
  const [mode, setMode] = useState<AppMode>(AppMode.DICTIONARY);
  const [history, setHistory] = useState<LexicalEntry[]>([]);
  const [activeEntry, setActiveEntry] = useState<LexicalEntry | null>(null);
  const [autoAudio, setAutoAudio] = useState(() => localStorage.getItem('autoAudio') === 'true');
  const [isSyncing, setIsSyncing] = useState(false);
  const [cloudActive, setCloudActive] = useState(false);

  const initialHydrationRef = useRef(false);

  const [profile, setProfile] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('lexProfile');
    return saved ? JSON.parse(saved) : {
      username: 'Scholar',
      xp: 0,
      rank: RANKS[0].title,
      searchCount: 0,
      arenaWins: 0,
      accuracy: 100,
      streak: 0
    };
  });

  useEffect(() => {
    const handleFirstInteraction = async () => {
      await resumeAudioContext();
      document.removeEventListener('touchstart', handleFirstInteraction);
      document.removeEventListener('mousedown', handleFirstInteraction);
    };
    document.addEventListener('touchstart', handleFirstInteraction);
    document.addEventListener('mousedown', handleFirstInteraction);
    return () => {
      document.removeEventListener('touchstart', handleFirstInteraction);
      document.removeEventListener('mousedown', handleFirstInteraction);
    };
  }, []);

  const syncProfileToCloud = useCallback(async (newProfile: UserProfile) => {
    if (!newProfile.telegramId) return;
    setIsSyncing(true);
    try {
      await upsertProfile(newProfile);
      setCloudActive(true);
    } catch (err) {
      console.error("Cloud Archive Sync Failed:", err);
      setCloudActive(false);
    } finally {
      setIsSyncing(false);
    }
  }, []);

  useEffect(() => {
    if (initialHydrationRef.current) return;
    initialHydrationRef.current = true;

    const performHydration = async () => {
      const savedHistory = localStorage.getItem('lexHistory');
      if (savedHistory) setHistory(JSON.parse(savedHistory));

      const tgUser = isTelegramEnvironment() ? getTelegramUser() : null;
      if (tgUser) {
        initTelegramTheme();
        setIsSyncing(true);
        try {
          const [cloudProf, cloudHist] = await Promise.all([
            fetchProfile(tgUser.id),
            fetchUserHistory(tgUser.id)
          ]);

          let finalProfile: UserProfile;

          if (cloudProf) {
            finalProfile = {
              ...cloudProf,
              username: tgUser.username || cloudProf.username,
              firstName: tgUser.first_name || cloudProf.firstName,
              lastName: tgUser.last_name || cloudProf.lastName,
              languageCode: tgUser.language_code || cloudProf.languageCode,
              telegramId: tgUser.id
            };
            setCloudActive(true);
          } else {
            finalProfile = {
              username: tgUser.username || 'Scholar',
              firstName: tgUser.first_name || '',
              lastName: tgUser.last_name || '',
              telegramId: tgUser.id,
              languageCode: tgUser.language_code || 'en',
              xp: profile.xp,
              rank: profile.rank,
              searchCount: profile.searchCount,
              arenaWins: profile.arenaWins,
              accuracy: profile.accuracy,
              streak: profile.streak
            };
          }

          setProfile(finalProfile);
          await upsertProfile(finalProfile);
          setCloudActive(true);

          if (cloudHist && cloudHist.length > 0) {
            setHistory(prev => {
              const combined = [...cloudHist, ...prev];
              const uniqueMap = new Map();
              combined.forEach(item => {
                const key = `${item.term}-${item.sourceLang}-${item.targetLang}`;
                if (!uniqueMap.has(key)) uniqueMap.set(key, item);
              });
              return Array.from(uniqueMap.values()).slice(0, 50);
            });
          }
        } catch (err) {
          console.error("Archival connection failure:", err);
          setCloudActive(false);
        } finally {
          setIsSyncing(false);
        }
      }
    };

    performHydration();
  }, []);

  useEffect(() => {
    localStorage.setItem('lexHistory', JSON.stringify(history));
  }, [history]);

  useEffect(() => {
    localStorage.setItem('lexProfile', JSON.stringify(profile));
    if (profile.telegramId) {
      syncProfileToCloud(profile);
    }
  }, [profile, syncProfileToCloud]);

  useEffect(() => {
    localStorage.setItem('autoAudio', String(autoAudio));
  }, [autoAudio]);

  const addEntry = async (entry: LexicalEntry) => {
    setHistory(prev => {
      const filtered = prev.filter(p => p.term.toLowerCase() !== entry.term.toLowerCase());
      return [entry, ...filtered].slice(0, 50);
    });

    const newXp = profile.xp + 2;
    const newRank = RANKS.reduce((prev, curr) => newXp >= curr.minXp ? curr : prev, RANKS[0]);
    const newProfile = { 
      ...profile, 
      xp: newXp, 
      rank: newRank.title,
      searchCount: profile.searchCount + 1 
    };

    setProfile(newProfile);

    if (newProfile.telegramId) {
      try {
        await saveUserHistoryEntry(newProfile.telegramId, entry);
      } catch (err) {
        console.warn("Cloud persistence failed.");
      }
    }
  };

  const handleArenaResult = (correctCount: number, totalQuestions: number) => {
    const earnedXp = correctCount * 5;
    const sessionAccuracy = totalQuestions > 0 ? (correctCount / totalQuestions) * 100 : 0;

    const newXp = profile.xp + earnedXp;
    const newRank = RANKS.reduce((prev, curr) => newXp >= curr.minXp ? curr : prev, RANKS[0]);
    const newAccuracy = profile.accuracy === 100 ? sessionAccuracy : (profile.accuracy + sessionAccuracy) / 2;

    const newProfile = { 
      ...profile, 
      xp: newXp, 
      rank: newRank.title,
      arenaWins: profile.arenaWins + 1,
      accuracy: Math.round(newAccuracy),
      streak: correctCount === totalQuestions ? profile.streak + 1 : 0
    };

    setProfile(newProfile);
  };

  const handleHistoryItemClick = (entry: LexicalEntry) => {
    setActiveEntry(entry);
    setMode(AppMode.DICTIONARY);
  };

  return (
    <div className="min-h-screen bg-[#fcfcfb] flex flex-col selection:bg-[#7c1a1a]/10 selection:text-[#7c1a1a]">
      <header className="px-6 md:px-12 pt-8 pb-4 pt-safe max-w-[1400px] mx-auto w-full">
        <div className="flex items-center gap-6 mb-8">
          <span 
            onClick={() => { setActiveEntry(null); setMode(AppMode.DICTIONARY); triggerHaptic('light'); }}
            className="text-3xl md:text-4xl serif font-black tracking-tighter cursor-pointer text-[#7c1a1a]"
          >
            LEX.
          </span>
          <div className="flex flex-col">
            <span className="text-[10px] uppercase tracking-[0.4em] text-stone-900 font-black leading-none mb-1">
              Polyglot Insight Engine
            </span>
            <span className="text-[8px] uppercase tracking-[0.2em] text-stone-300 font-bold">
              Archival Philology
            </span>
          </div>
        </div>

        <nav className="flex items-center gap-8 text-[10px] uppercase tracking-[0.2em] font-black text-stone-400 border-b border-stone-100">
          <button 
            onClick={() => { setActiveEntry(null); setMode(AppMode.DICTIONARY); triggerHaptic('light'); }} 
            className={`pb-3 transition-all border-b-2 ${mode === AppMode.DICTIONARY ? 'border-[#7c1a1a] text-stone-900' : 'border-transparent'}`}
          >
            Encyclopedia
          </button>
          <button 
            onClick={() => { setMode(AppMode.ARENA); triggerHaptic('light'); }} 
            className={`pb-3 transition-all border-b-2 ${mode === AppMode.ARENA ? 'border-[#7c1a1a] text-stone-900' : 'border-transparent'}`}
          >
            Arena
          </button>
          <button 
            onClick={() => { setMode(AppMode.ARCHIVE); triggerHaptic('light'); }} 
            className={`pb-3 transition-all border-b-2 ${mode === AppMode.ARCHIVE ? 'border-[#7c1a1a] text-stone-900' : 'border-transparent'}`}
          >
            Chronicles
          </button>
          <button 
            onClick={() => openTelegramLink('https://t.me/lex_uz_support')} 
            className="pb-3 border-b-2 border-transparent flex items-center gap-1"
          >
            Support <svg xmlns="http://www.w3.org/2000/svg" width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M15 3h6v6"/><path d="M10 14L21 3"/><path d="M18 13v6a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h6"/></svg>
          </button>
        </nav>
      </header>

      <main className="flex-1">
        <div className="max-w-[1400px] mx-auto px-6 md:px-12 pb-20">
          {mode === AppMode.DICTIONARY && (
            <Dictionary 
              onEntrySaved={addEntry} 
              autoAudio={autoAudio} 
              setAutoAudio={setAutoAudio}
              profile={profile}
              history={history}
              onStartArena={() => setMode(AppMode.ARENA)}
              selectedEntry={activeEntry}
              onEntryClick={handleHistoryItemClick}
            />
          )}

          {mode === AppMode.ARENA && (
            <Arena history={history} onResult={handleArenaResult} />
          )}

          {mode === AppMode.ARCHIVE && (
            <Archive history={history} onEntryClick={handleHistoryItemClick} />
          )}
        </div>
      </main>

      <footer className="py-8 border-t border-stone-100 bg-white/50 pb-safe">
        <div className="max-w-[1400px] mx-auto px-6 md:px-12 flex flex-col md:flex-row justify-between items-center gap-4 text-[9px] uppercase tracking-[0.3em] text-stone-400 font-black">
          <div className="flex items-center gap-6">
             <span>&copy; 2025 LEXICON PHILOLOGY</span>
             <span className={`flex items-center gap-2 ${isSyncing ? 'text-[#7c1a1a] animate-pulse' : ''}`}>
               <span className={`w-2 h-2 rounded-full ${isSyncing ? 'bg-[#7c1a1a]' : cloudActive ? 'bg-green-500' : 'bg-stone-200'}`} />
               {isSyncing ? 'Syncing...' : cloudActive ? 'Cloud Active' : 'Offline'}
             </span>
          </div>
          <div className="flex items-center gap-8">
            <span className="text-stone-900">{profile.rank}</span>
            <span>LVL {Math.floor(profile.xp / 1000) + 1}</span>
