  autoAudio, 
  setAutoAudio, 
  profile, 
  history, 
  onStartArena, 
  selectedEntry,
  onEntryClick
}) => {
  const [query, setQuery] = useState('');
  const [sourceLang, setSourceLang] = useState<Language>('German');
  const [targetLang, setTargetLang] = useState<Language>('Uzbek');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<LexicalEntry | null>(null);
  const [suggestions, setSuggestions] = useState<SuggestionItem[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [selectedIndex, setSelectedIndex] = useState(-1);
  const [isListening, setIsListening] = useState(false);
  const [micDenied, setMicDenied] = useState(false);

  const suggestionRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (selectedEntry) {
      setQuery(selectedEntry.term);
      setResult(selectedEntry);
      setSourceLang(selectedEntry.sourceLang);
      setTargetLang(selectedEntry.targetLang);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  }, [selectedEntry]);

  useEffect(() => {
    const delayDebounce = setTimeout(async () => {
      const trimmedQuery = query.trim().toLowerCase();
      if (trimmedQuery.length >= 2) {
        const localMatches = history
          .filter(e => e.sourceLang === sourceLang && e.term.toLowerCase().includes(trimmedQuery))
          .map(e => ({ term: e.term, source: 'local' as const }));

        const seedMatches = Object.values(SEED_ARCHIVE)
          .filter(e => e?.term && e.term.toLowerCase().includes(trimmedQuery))
          .map(e => ({ term: e!.term!, source: 'seed' as const }));

        let globalMatches: SuggestionItem[] = [];
        try {
          const globalTerms = await fetchSuggestions(query, sourceLang);
          globalMatches = globalTerms.map(term => ({ term, source: 'global' as const }));
        } catch (e) {
          console.warn("Global suggestions fetch failed");
        }

        const combined = [...localMatches, ...seedMatches, ...globalMatches];
        const unique = combined.filter((v, i, a) => 
          a.findIndex(t => t.term.toLowerCase() === v.term.toLowerCase()) === i
        ).slice(0, 8);

        setSuggestions(unique);
        setShowSuggestions(unique.length > 0);
        setSelectedIndex(-1);
      } else {
        setSuggestions([]);
        setShowSuggestions(false);
      }
    }, 250);
    return () => clearTimeout(delayDebounce);
  }, [query, sourceLang, history]);

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (suggestionRef.current && !suggestionRef.current.contains(e.target as Node)) {
        setShowSuggestions(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleSourceLangChange = useCallback(async (lang: Language) => {
    await resumeAudioContext();
    if (lang === targetLang) setTargetLang(sourceLang);
    setSourceLang(lang);
    triggerHaptic('light');
  }, [sourceLang, targetLang]);

  const handleTargetLangChange = useCallback(async (lang: Language) => {
    await resumeAudioContext();
    if (lang === sourceLang) setSourceLang(targetLang);
    setTargetLang(lang);
    triggerHaptic('light');
  }, [sourceLang, targetLang]);

  const localCache = useMemo(() => {
    const cache = new Map<string, LexicalEntry>();
    Object.entries(SEED_ARCHIVE).forEach(([key, entry]) => {
      const parts = key.split('-');
      const sL = parts[1] as Language;
      const tL = parts[2] as Language;
      if (entry.term) {
        const norm = normalize(entry.term, sL);
        cache.set(`${norm}-${sL}-${tL}`, { ...entry, id: `seed-${key}`, normalizedTerm: norm, sourceLang: sL, targetLang: tL } as any);
      }
    });
    history.forEach(entry => {
      const norm = normalize(entry.term, entry.sourceLang);
      cache.set(`${norm}-${entry.sourceLang}-${entry.targetLang}`, entry);
    });
    return cache;
  }, [history]);

  const handleSearch = async (overrideQuery?: string) => {
    const cleanQuery = (overrideQuery || query).trim();
    if (!cleanQuery) return;

    if (inputRef.current) inputRef.current.blur();

    await resumeAudioContext();
    setShowSuggestions(false);
    setQuery(cleanQuery);

    if (autoAudio) {
      speak(cleanQuery, sourceLang).catch(() => {});
    }

    const normQuery = normalize(cleanQuery, sourceLang);
    const cacheKey = `${normQuery}-${sourceLang}-${targetLang}`;

    const localHit = localCache.get(cacheKey);
    if (localHit) {
      setResult(localHit);
      if (autoAudio) {
        setTimeout(() => speak(localHit.mainTranslation, targetLang).catch(() => {}), 400);
      }
      return;
    }

    setLoading(true);
    setResult(null);

    try {
      const globalHit = await fetchGlobalEntry(normQuery, sourceLang, targetLang);
      if (globalHit) {
        setResult(globalHit);
        onEntrySaved(globalHit);
        setLoading(false);
        if (autoAudio) {
          setTimeout(() => speak(globalHit.mainTranslation, targetLang).catch(() => {}), 400);
        }
        return;
      }

      const finalEntry = await translateWord(cleanQuery, sourceLang, targetLang);
      finalEntry.normalizedTerm = normQuery;

      setResult(finalEntry);
      onEntrySaved(finalEntry);
      saveGlobalEntry(finalEntry);

      if (autoAudio) {
        setTimeout(() => speak(finalEntry.mainTranslation, targetLang).catch(() => {}), 400);
      }
    } catch (err) {
      console.error("Philologist Engine Error:", err);
      triggerHaptic('error');
    } finally {
      setLoading(false);
    }
  };

  const startVoiceSearch = async () => {
    if (isListening) return;
    setMicDenied(false);

    // Initial permission priming
    if (!globalMicPrimed) {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        stream.getTracks().forEach(track => track.stop());
        globalMicPrimed = true;
      } catch (err) {
        console.error("Linguistic access denied:", err);
        setMicDenied(true);
        triggerHaptic('error');
        return;
      }
    }

    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      alert("Linguistic transcription not supported in this vessel.");
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.lang = sourceLang === 'German' ? 'de-DE' : sourceLang === 'Russian' ? 'ru-RU' : sourceLang === 'Uzbek' ? 'uz-UZ' : 'en-US';
    recognition.interimResults = false;
    recognition.maxAlternatives = 1;

    recognition.onstart = () => {
      setIsListening(true);
      triggerHaptic('medium');
    };

    recognition.onresult = (event: any) => {
      const speechToText = event.results[0][0].transcript;
      setQuery(speechToText);
      handleSearch(speechToText);
    };

    recognition.onerror = (event: any) => {
      setIsListening(false);
      if (event.error === 'not-allowed') {
        setMicDenied(true);
        globalMicPrimed = false; // Reset so they can try re-priming
      }
      if (event.error !== 'no-speech') triggerHaptic('error');
    };

    recognition.onend = () => setIsListening(false);

    try {
      recognition.start();
    } catch (e) {
      setIsListening(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      resumeAudioContext(); 
    }
    if (!showSuggestions) return;

    if (e.key === 'ArrowDown') {
      e.preventDefault();
      setSelectedIndex(prev => (prev + 1) % suggestions.length);
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      setSelectedIndex(prev => (prev - 1 + suggestions.length) % suggestions.length);
    } else if (e.key === 'Enter' && selectedIndex >= 0) {
      e.preventDefault();
      const selected = suggestions[selectedIndex];
      setQuery(selected.term);
      handleSearch(selected.term);
    } else if (e.key === 'Escape') {
      setShowSuggestions(false);
    }
  };

  const swapLanguages = useCallback(async () => {
    await resumeAudioContext();
    setSourceLang(prevS => {
      const currentT = targetLang;
      setTargetLang(prevS);
      return currentT;
    });
    triggerHaptic('medium');
  }, [targetLang]);

  return (
    <div className="space-y-8 md:space-y-16 max-w-7xl mx-auto contain-layout">
      {/* Philological Mastery Block */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-8 pt-4">
        <div className="flex items-center gap-6">
          <div className="space-y-1 border-l-2 border-[#7c1a1a] pl-4 block">
            <span className="text-[8px] uppercase tracking-[0.4em] text-stone-300 font-bold block mb-1">Philological Mastery</span>
            <div className="flex items-baseline gap-2">
              <span className="text-xl md:text-2xl font-black serif text-stone-900 leading-none">{profile.xp}</span>
              <span className="text-[7px] uppercase tracking-[0.2em] text-stone-200 font-bold">Total XP</span>
            </div>
          </div>
        </div>

        <div className="flex flex-col lg:flex-row items-center gap-6 lg:gap-12 w-full md:w-auto">
          {/* Language Grids */}
          <div className="flex flex-col sm:flex-row items-center gap-4 bg-stone-50 p-2 rounded-sm w-full sm:w-auto border border-stone-100 shadow-inner">
             <div className="grid grid-cols-4 bg-stone-900 rounded-sm overflow-hidden w-full sm:w-auto ring-1 ring-stone-900">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button key={`src-${full}`} type="button" onClick={() => handleSourceLangChange(full)}
                    className={`px-3 sm:px-5 py-2.5 text-[9px] font-black tracking-widest border-r border-stone-800 last:border-r-0 transition-all ${sourceLang === full ? 'bg-stone-900 text-white' : 'bg-white text-stone-300 hover:text-stone-600'}`}>
                    {short}
                  </button>
                ))}
             </div>
             <button type="button" onClick={swapLanguages} className="text-stone-300 hover:text-stone-900 transition-all p-2 hover:rotate-180 duration-500 transform sm:rotate-0 rotate-90 active:scale-90">
               <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="m17 2 4 4-4 4"/><path d="M3 11v-1a4 4 0 0 1 4-4h14"/><path d="m7 22-4-4 4-4"/><path d="M21 13v1a4 4 0 0 1-4 4H3"/></svg>
             </button>
             <div className="grid grid-cols-4 bg-[#7c1a1a] rounded-sm overflow-hidden w-full sm:w-auto ring-1 ring-[#7c1a1a]">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button key={`trg-${full}`} type="button" onClick={() => handleTargetLangChange(full)}
                    className={`px-3 sm:px-5 py-2.5 text-[9px] font-black tracking-widest border-r border-[#8b2222] last:border-r-0 transition-all ${targetLang === full ? 'bg-[#7c1a1a] text-white' : 'bg-white text-stone-300 hover:text-stone-600'}`}>
                    {short}
                  </button>
                ))}
             </div>
          </div>

          <div className="flex items-center gap-4">
            <span className="text-[9px] uppercase tracking-widest text-stone-400 font-bold">Auto-Pronounce</span>
            <button onClick={async () => { await resumeAudioContext(); setAutoAudio(!autoAudio); triggerHaptic('light'); }} className={`w-10 h-5 rounded-full relative transition-all duration-300 p-1 ${autoAudio ? 'bg-[#7c1a1a]' : 'bg-stone-200'}`}>
              <div className={`w-3 h-3 bg-white rounded-full transition-all shadow-md ${autoAudio ? 'translate-x-5' : 'translate-x-0'}`} />
            </button>
          </div>
        </div>
      </div>

      <div className="relative w-full" ref={suggestionRef}>
        {/* Search Bar (No Italics) */}
        <div className={`relative flex items-center bg-stone-50/30 border border-stone-100 rounded-sm overflow-hidden shadow-sm transition-all focus-within:ring-4 focus-within:ring-[#7c1a1a]/5 ${isListening ? 'ring-4 ring-[#7c1a1a]/20' : ''}`}>
          <input 
            ref={inputRef}
            type="text" 
            value={query} 
            onChange={(e) => setQuery(e.target.value)} 
            onFocus={async () => { await resumeAudioContext(); if (suggestions.length > 0) setShowSuggestions(true); }}
            onKeyDown={handleKeyDown}
            placeholder={isListening ? "Listening..." : "summon an inscription..."}
            className="flex-1 pl-8 py-6 text-xl md:text-2xl serif bg-transparent text-stone-900 placeholder:text-stone-200 outline-none" 
          />
          <div className="flex items-center">
            <button 
              type="button" 
              onClick={startVoiceSearch}
              className={`p-6 transition-all ${isListening ? 'text-[#7c1a1a] animate-pulse' : 'text-stone-300 hover:text-[#7c1a1a]'}`}
              title="Voice Search"
            >
              <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2a3 3 0 0 0-3 3v7a3 3 0 0 0 6 0V5a3 3 0 0 0-3-3Z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" x2="12" y1="19" y2="22"/></svg>
            </button>
            <button 
              onClick={() => handleSearch()} 
              disabled={loading} 
              className="px-10 py-6 border-l border-stone-100 bg-stone-50/50 text-stone-400 hover:text-stone-900 transition-all flex items-center justify-center"
            >
              {loading ? <div className="w-5 h-5 border-2 border-stone-900 border-t-transparent rounded-full animate-spin" /> : <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M5 12h14"/><path d="m12 5 7 7-7 7"/></svg>}
            </button>
          </div>
        </div>

        {/* User-friendly Mic Access Notice */}
        {micDenied && (
          <div className="mt-4 p-5 bg-stone-900 text-white rounded-sm flex flex-col md:flex-row items-center justify-between gap-4 animate-in fade-in slide-in-from-top-2 duration-300 border-l-4 border-[#7c1a1a]">
            <div className="flex items-center gap-4">
              <span className="text-xl">🎙️</span>
              <p className="text-[10px] uppercase tracking-widest font-black leading-relaxed">
                Microphone access is required for scholarly transcription. Please enable permissions in your vessel's settings to utilize voice features.
              </p>
            </div>
            <button 
              onClick={startVoiceSearch} 
              className="bg-[#7c1a1a] hover:bg-[#9a2121] px-6 py-2.5 text-[9px] font-black uppercase tracking-[0.2em] rounded-sm whitespace-nowrap transition-colors"
            >
              Authorize & Try Again
            </button>
          </div>
        )}

        {showSuggestions && (
          <div className="absolute top-full left-0 right-0 bg-white border border-stone-200 shadow-2xl z-[100] animate-in fade-in slide-in-from-top-1 rounded-b-sm overflow-hidden max-h-[400px] overflow-y-auto">
             {suggestions.map((s, idx) => (
               <button 
                 key={idx} 
                 onClick={() => { setQuery(s.term); handleSearch(s.term); }}
                 onMouseEnter={() => setSelectedIndex(idx)}
                 className={`w-full text-left px-8 py-4 hover:bg-stone-50 border-b border-stone-50 last:border-0 flex items-center justify-between group transition-all ${selectedIndex === idx ? 'bg-stone-50' : ''}`}
               >
                 <span className="serif text-lg text-stone-900">{s.term}</span>
                 <span className={`text-[8px] uppercase tracking-widest font-black px-2 py-1 rounded-sm ${s.source === 'local' ? 'text-[#7c1a1a]' : 'text-stone-300'}`}>
                   {s.source === 'local' ? 'Archive' : 'Global'}
                 </span>
               </button>
             ))}
          </div>
        )}
      </div>

      <div className="min-h-[100px]">
        {loading && (
          <div className="py-20 flex flex-col items-center justify-center space-y-6 animate-pulse">
            <div className="w-12 h-12 border-2 border-[#7c1a1a] border-t-transparent rounded-full animate-spin"></div>
            <p className="text-[10px] uppercase tracking-[0.4em] text-stone-300 font-black">Consulting the Archives...</p>
          </div>
        )}
        {result && !loading && <ResultCard entry={result} onSearchTerm={(term) => handleSearch(term)} />}
        {!result && !loading && (
          <div className="py-24 text-center space-y-4">
            <h2 className="serif text-5xl font-black text-stone-900 tracking-tight lowercase">scholarly discovery</h2>
            <p className="text-stone-300 serif italic text-xl max-w-lg mx-auto leading-relaxed">
              The engine awaits your command. Search for etymologies, or test your mastery in the <button onClick={onStartArena} className="text-[#7c1a1a] underline underline-offset-8 decoration-1 hover:text-stone-900 transition-colors">Scholarly Arena</button>.
            </p>
          </div>
        )}
      </div>

      <div className="pt-16 border-t border-stone-100">
        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-8 mb-12">
          <div className="border-l-[2px] border-[#7c1a1a] pl-6 py-1">
            <h2 className="text-[11px] uppercase tracking-[0.5em] text-stone-900 font-black">Archival Chronicles</h2>
            <p className="text-stone-300 text-[9px] uppercase tracking-[0.2em] font-bold block mt-1">Persistent insights</p>
          </div>
          <button 
            onClick={async () => { await resumeAudioContext(); onStartArena(); }} 
            className="bg-[#7c1a1a] text-white px-10 py-5 flex items-center gap-4 shadow-lg hover:shadow-[#7c1a1a]/20 transition-all rounded-sm w-full sm:w-auto justify-center font-black text-[10px] uppercase tracking-[0.4em] active:scale-[0.98]"
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="currentColor"><path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z"/></svg>
            Start Arena
          </button>
        </div>
        <HistoryGrid history={history} onEntryClick={onEntryClick} />
      </div>
    </div>
  );
};

export default Dictionary;

import React, { useState, useMemo, useEffect, useRef, useCallback } from 'react';
import { Language, LexicalEntry, UserProfile } from '../types';
import { translateWord } from '../services/gemini';
import { speak, resumeAudioContext } from '../services/tts';
import { SEED_ARCHIVE } from '../constants';
import { fetchGlobalEntry, saveGlobalEntry, fetchSuggestions } from '../services/supabase';
import ResultCard from './ResultCard';
import HistoryGrid from './HistoryGrid';
import { triggerHaptic } from '../services/telegram';

interface Props {
  onEntrySaved: (entry: LexicalEntry) => void;
  autoAudio: boolean;
  setAutoAudio: (val: boolean) => void;
  profile: UserProfile;
  history: LexicalEntry[];
  onStartArena: () => void;
  selectedEntry?: LexicalEntry | null;
  onEntryClick: (entry: LexicalEntry) => void;
}

interface SuggestionItem {
  term: string;
  source: 'local' | 'global' | 'seed';
}

const LANGUAGES: Record<Language, string> = {
  German: 'GER',
  Uzbek: 'UZB',
  English: 'ENG',
  Russian: 'RUS'
};

const normalize = (text: string, lang: Language): string => {
  let res = text.trim().toLowerCase();
  if (lang === 'German') {
    res = res.replace(/ä/g, 'ae').replace(/ö/g, 'oe').replace(/ü/g, 'ue').replace(/ß/g, 'ss');
  } else if (lang === 'Russian') {
    res = res.replace(/ё/g, 'е');
  } else if (lang === 'Uzbek') {
    res = res.replace(/[‘’`]/g, "'");
  }
  return res;
};

// Persistent reference to the audio stream to avoid repeated permission prompts
let activeMicStream: MediaStream | null = null;

const Dictionary: React.FC<Props> = ({ 
  onEntrySaved, 
  autoAudio, 
  setAutoAudio, 
  profile, 
  history, 
  onStartArena, 
  selectedEntry,
  onEntryClick
}) => {
  const [query, setQuery] = useState('');
  const [sourceLang, setSourceLang] = useState<Language>('German');
  const [targetLang, setTargetLang] = useState<Language>('Uzbek');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<LexicalEntry | null>(null);
  const [suggestions, setSuggestions] = useState<SuggestionItem[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [selectedIndex, setSelectedIndex] = useState(-1);
  const [isListening, setIsListening] = useState(false);
  const [micDenied, setMicDenied] = useState(false);

  const suggestionRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (selectedEntry) {
      setQuery(selectedEntry.term);
      setResult(selectedEntry);
      setSourceLang(selectedEntry.sourceLang);
      setTargetLang(selectedEntry.targetLang);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  }, [selectedEntry]);

  useEffect(() => {
    const delayDebounce = setTimeout(async () => {
      const trimmedQuery = query.trim().toLowerCase();
      if (trimmedQuery.length >= 2) {
        const localMatches = history
          .filter(e => e.sourceLang === sourceLang && e.term.toLowerCase().includes(trimmedQuery))
          .map(e => ({ term: e.term, source: 'local' as const }));

        const seedMatches = Object.values(SEED_ARCHIVE)
          .filter(e => e?.term && e.term.toLowerCase().includes(trimmedQuery))
          .map(e => ({ term: e!.term!, source: 'seed' as const }));

        let globalMatches: SuggestionItem[] = [];
        try {
          const globalTerms = await fetchSuggestions(query, sourceLang);
          globalMatches = globalTerms.map(term => ({ term, source: 'global' as const }));
        } catch (e) {
          console.warn("Global suggestions fetch failed");
        }

        const combined = [...localMatches, ...seedMatches, ...globalMatches];
        const unique = combined.filter((v, i, a) => 
          a.findIndex(t => t.term.toLowerCase() === v.term.toLowerCase()) === i
        ).slice(0, 8);

        setSuggestions(unique);
        setShowSuggestions(unique.length > 0);
        setSelectedIndex(-1);
      } else {
        setSuggestions([]);
        setShowSuggestions(false);
      }
    }, 250);
    return () => clearTimeout(delayDebounce);
  }, [query, sourceLang, history]);

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (suggestionRef.current && !suggestionRef.current.contains(e.target as Node)) {
        setShowSuggestions(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleSourceLangChange = useCallback(async (lang: Language) => {
    await resumeAudioContext();
    if (lang === targetLang) setTargetLang(sourceLang);
    setSourceLang(lang);
    triggerHaptic('light');
  }, [sourceLang, targetLang]);

  const handleTargetLangChange = useCallback(async (lang: Language) => {
    await resumeAudioContext();
    if (lang === sourceLang) setSourceLang(targetLang);
    setTargetLang(lang);
    triggerHaptic('light');
  }, [sourceLang, targetLang]);

  const localCache = useMemo(() => {
    const cache = new Map<string, LexicalEntry>();
    Object.entries(SEED_ARCHIVE).forEach(([key, entry]) => {
      const parts = key.split('-');
      const sL = parts[1] as Language;
      const tL = parts[2] as Language;
      if (entry.term) {
        const norm = normalize(entry.term, sL);
        cache.set(`${norm}-${sL}-${tL}`, { ...entry, id: `seed-${key}`, normalizedTerm: norm, sourceLang: sL, targetLang: tL } as any);
      }
    });
    history.forEach(entry => {
      const norm = normalize(entry.term, entry.sourceLang);
      cache.set(`${norm}-${entry.sourceLang}-${entry.targetLang}`, entry);
    });
    return cache;
  }, [history]);

  const handleSearch = async (overrideQuery?: string) => {
    const cleanQuery = (overrideQuery || query).trim();
    if (!cleanQuery) return;

    if (inputRef.current) inputRef.current.blur();

    await resumeAudioContext();
    setShowSuggestions(false);
    setQuery(cleanQuery);

    if (autoAudio) {
      speak(cleanQuery, sourceLang).catch(() => {});
    }

    const normQuery = normalize(cleanQuery, sourceLang);
    const cacheKey = `${normQuery}-${sourceLang}-${targetLang}`;

    const localHit = localCache.get(cacheKey);
    if (localHit) {
      setResult(localHit);
      if (autoAudio) {
        setTimeout(() => speak(localHit.mainTranslation, targetLang).catch(() => {}), 400);
      }
      return;
    }

    setLoading(true);
    setResult(null);

    try {
      const globalHit = await fetchGlobalEntry(normQuery, sourceLang, targetLang);
      if (globalHit) {
        setResult(globalHit);
        onEntrySaved(globalHit);
        setLoading(false);
        if (autoAudio) {
          setTimeout(() => speak(globalHit.mainTranslation, targetLang).catch(() => {}), 400);
        }
        return;
      }

      const finalEntry = await translateWord(cleanQuery, sourceLang, targetLang);
      finalEntry.normalizedTerm = normQuery;

      setResult(finalEntry);
      onEntrySaved(finalEntry);
      saveGlobalEntry(finalEntry);

      if (autoAudio) {
        setTimeout(() => speak(finalEntry.mainTranslation, targetLang).catch(() => {}), 400);
      }
    } catch (err) {
      console.error("Philologist Engine Error:", err);
      triggerHaptic('error');
    } finally {
      setLoading(false);
    }
  };

  const startVoiceSearch = async () => {
    if (isListening) return;
    setMicDenied(false);

    // Request mic permission only once and reuse the stream
    if (!activeMicStream) {
      try {
        activeMicStream = await navigator.mediaDevices.getUserMedia({ audio: true });
      } catch (err) {
        console.error("Linguistic access denied:", err);
        setMicDenied(true);
        triggerHaptic('error');
        return;
      }
    }

    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      alert("Linguistic transcription not supported in this vessel.");
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.lang = sourceLang === 'German' ? 'de-DE' : sourceLang === 'Russian' ? 'ru-RU' : sourceLang === 'Uzbek' ? 'uz-UZ' : 'en-US';
    recognition.interimResults = false;
    recognition.maxAlternatives = 1;

    recognition.onstart = () => {
      setIsListening(true);
      triggerHaptic('medium');
    };

    recognition.onresult = (event: any) => {
      const speechToText = event.results[0][0].transcript;
      setQuery(speechToText);
      handleSearch(speechToText);
    };

    recognition.onerror = (event: any) => {
      setIsListening(false);
      if (event.error === 'not-allowed') {
        setMicDenied(true);
        activeMicStream = null; 
      }
      if (event.error !== 'no-speech') triggerHaptic('error');
    };

    recognition.onend = () => {
      setIsListening(false);
    };

    recognition.start();
  };

  return (
    <div className="space-y-8">
      {/* Search Header */}
      <div className="relative z-20">
        <div className="flex flex-col md:flex-row gap-4 mb-6">
          <div className="flex-1 relative" ref={suggestionRef}>
            <div className="relative">
              <input
                ref={inputRef}
                type="text"
                value={query}
                onChange={(e) => setQuery(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter') handleSearch();
                  if (e.key === 'ArrowDown' && showSuggestions) {
                    setSelectedIndex(prev => Math.min(prev + 1, suggestions.length - 1));
                  }
                  if (e.key === 'ArrowUp' && showSuggestions) {
                    setSelectedIndex(prev => Math.max(prev - 1, 0));
                  }
                }}
                onFocus={() => query.length >= 2 && setShowSuggestions(true)}
                placeholder="Search the archive..."
                className="w-full bg-white border border-stone-200 px-6 py-5 md:py-6 text-xl md:text-2xl serif italic focus:outline-none focus:border-[#7c1a1a] transition-all shadow-sm rounded-sm pr-24"
              />
              <div className="absolute right-4 top-1/2 -translate-y-1/2 flex items-center gap-2">
                {loading ? (
                  <div className="w-5 h-5 border-2 border-[#7c1a1a] border-t-transparent rounded-full animate-spin" />
                ) : (
                  <>
                    <button 
                      onClick={startVoiceSearch}
                      className={`p-2 transition-all rounded-full ${isListening ? 'bg-[#7c1a1a] text-white animate-pulse' : 'text-stone-300 hover:text-[#7c1a1a] hover:bg-stone-50'}`}
                      title="Voice Search"
                    >
                      <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2a3 3 0 0 0-3 3v7a3 3 0 0 0 6 0V5a3 3 0 0 0-3-3z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" y1="19" x2="12" y2="22"/><line x1="8" y1="22" x2="16" y2="22"/></svg>
                    </button>
                    <button 
                      onClick={() => handleSearch()}
                      className="p-2 text-stone-300 hover:text-[#7c1a1a] transition-all hover:bg-stone-50 rounded-full"
                    >
                      <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg>
                    </button>
                  </>
                )}
              </div>
            </div>

            {showSuggestions && suggestions.length > 0 && (
              <div className="absolute top-full left-0 w-full bg-white border border-stone-200 mt-1 shadow-xl rounded-sm overflow-hidden z-50">
                {suggestions.map((item, idx) => (
                  <div
                    key={idx}
                    onClick={() => handleSearch(item.term)}
                    onMouseEnter={() => setSelectedIndex(idx)}
                    className={`px-6 py-4 cursor-pointer flex justify-between items-center transition-colors ${selectedIndex === idx ? 'bg-stone-50' : ''}`}
                  >
                    <span className="serif text-lg text-stone-800">{item.term}</span>
                    <span className="text-[9px] uppercase tracking-widest text-stone-300 font-bold">{item.source}</span>
                  </div>
                ))}
              </div>
            )}
          </div>

          <div className="flex items-center bg-white border border-stone-200 rounded-sm p-1 shadow-sm">
            <div className="flex items-center gap-1">
              {(Object.keys(LANGUAGES) as Language[]).map((lang) => (
                <button
                  key={`src-${lang}`}
                  onClick={() => handleSourceLangChange(lang)}
                  className={`px-3 py-2 text-[10px] font-black tracking-widest transition-all rounded-sm ${sourceLang === lang ? 'bg-[#7c1a1a] text-white shadow-md' : 'text-stone-400 hover:text-stone-600'}`}
                >
                  {LANGUAGES[lang]}
                </button>
              ))}
            </div>

            <button 
              onClick={() => {
                const s = sourceLang;
                const t = targetLang;
                setSourceLang(t);
                setTargetLang(s);
                triggerHaptic('medium');
              }}
              className="px-2 text-stone-200 hover:text-[#7c1a1a] transition-colors"
            >
              <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="m7 16-4-4 4-4"/><path d="M3 12h18"/><path d="m17 8 4 4-4 4"/></svg>
            </button>

            <div className="flex items-center gap-1">
              {(Object.keys(LANGUAGES) as Language[]).map((lang) => (
                <button
                  key={`tgt-${lang}`}
                  onClick={() => handleTargetLangChange(lang)}
                  className={`px-3 py-2 text-[10px] font-black tracking-widest transition-all rounded-sm ${targetLang === lang ? 'bg-stone-900 text-white shadow-md' : 'text-stone-400 hover:text-stone-600'}`}
                >
                  {LANGUAGES[lang]}
                </button>
              ))}
            </div>
          </div>

          <button
            onClick={() => setAutoAudio(!autoAudio)}
            className={`px-4 py-2 border transition-all rounded-sm flex items-center gap-2 ${autoAudio ? 'border-[#7c1a1a] text-[#7c1a1a] bg-[#7c1a1a]/5' : 'border-stone-200 text-stone-300'}`}
          >
            <span className="text-[10px] font-black uppercase tracking-widest">Audio</span>
            <div className={`w-8 h-4 rounded-full relative transition-colors ${autoAudio ? 'bg-[#7c1a1a]' : 'bg-stone-200'}`}>
              <div className={`absolute top-1 w-2 h-2 bg-white rounded-full transition-all ${autoAudio ? 'left-5' : 'left-1'}`} />
            </div>
          </button>
        </div>
      </div>

      {micDenied && (
        <div className="bg-red-50 border border-red-100 p-4 text-center mb-6 animate-in slide-in-from-top-2">
          <p className="text-red-800 serif italic text-sm">Microphone access denied. Please verify permissions in your browser settings.</p>
        </div>
      )}

      {/* Results or Empty State */}
      <div className="min-h-[400px]">
        {loading ? (
          <div className="flex flex-col items-center justify-center py-32 animate-in fade-in duration-1000">
             <div className="w-12 h-12 border-4 border-stone-100 border-t-[#7c1a1a] rounded-full animate-spin mb-8" />
             <p className="serif text-2xl italic text-stone-300 animate-pulse">Summoning Linguistic Data...</p>
          </div>
        ) : result ? (
          <ResultCard entry={result} onSearchTerm={(term) => { setQuery(term); handleSearch(term); }} />
        ) : (
          <div className="space-y-12">
            {history.length > 0 ? (
              <section>
                <div className="flex justify-between items-center mb-8 border-b border-stone-100 pb-4">
                  <h3 className="text-[10px] uppercase tracking-[0.4em] text-stone-900 font-black">Recent Inscriptions</h3>
                  <button onClick={onStartArena} className="text-[9px] uppercase tracking-widest text-[#7c1a1a] font-bold hover:underline">Launch Arena →</button>
                </div>
                <HistoryGrid history={history.slice(0, 6)} onEntryClick={onEntryClick} />
              </section>
            ) : (
              <div className="py-20 text-center">
                 <p className="serif text-3xl italic text-stone-200 mb-4 font-light">The lexicon is silent.</p>
                 <p className="text-stone-300 text-[10px] uppercase tracking-[0.3em] font-black">Enter a query above to begin the philological journey</p>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default Dictionary;

import React, { useState, useMemo, useEffect, useRef, useCallback } from 'react';
import { Language, LexicalEntry, UserProfile } from '../types';
import { translateWord } from '../services/gemini';
import { speak, resumeAudioContext } from '../services/tts';
import { SEED_ARCHIVE } from '../constants';
import { fetchGlobalEntry, saveGlobalEntry, fetchSuggestions } from '../services/supabase';
import ResultCard from './ResultCard';
import HistoryGrid from './HistoryGrid';
import { triggerHaptic } from '../services/telegram';

interface Props {
  onEntrySaved: (entry: LexicalEntry) => void;
  autoAudio: boolean;
  setAutoAudio: (val: boolean) => void;
  profile: UserProfile;
  history: LexicalEntry[];
  onStartArena: () => void;
  selectedEntry?: LexicalEntry | null;
  onEntryClick: (entry: LexicalEntry) => void;
}

interface SuggestionItem {
  term: string;
  source: 'local' | 'global' | 'seed';
}

const LANGUAGES: Record<Language, string> = {
  German: 'GER',
  Uzbek: 'UZB',
  English: 'ENG',
  Russian: 'RUS'
};

const normalize = (text: string, lang: Language): string => {
  let res = text.trim().toLowerCase();
  if (lang === 'German') {
    res = res.replace(/ä/g, 'ae').replace(/ö/g, 'oe').replace(/ü/g, 'ue').replace(/ß/g, 'ss');
  } else if (lang === 'Russian') {
    res = res.replace(/ё/g, 'е');
  } else if (lang === 'Uzbek') {
    res = res.replace(/[‘’`]/g, "'");
  }
  return res;
};

// Persistent reference to the audio stream to avoid repeated permission prompts on iOS/Safari
let activeMicStream: MediaStream | null = null;

const Dictionary: React.FC<Props> = ({ 
  onEntrySaved, 
  autoAudio, 
  setAutoAudio, 
  profile, 
  history, 
  onStartArena, 
  selectedEntry,
  onEntryClick
}) => {
  const [query, setQuery] = useState('');
  const [sourceLang, setSourceLang] = useState<Language>('German');
  const [targetLang, setTargetLang] = useState<Language>('Uzbek');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<LexicalEntry | null>(null);
  const [suggestions, setSuggestions] = useState<SuggestionItem[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [selectedIndex, setSelectedIndex] = useState(-1);
  const [isListening, setIsListening] = useState(false);
  const [micDenied, setMicDenied] = useState(false);
  const [searchError, setSearchError] = useState<string | null>(null);

  const suggestionRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (selectedEntry) {
      setQuery(selectedEntry.term);
      setResult(selectedEntry);
      setSourceLang(selectedEntry.sourceLang);
      setTargetLang(selectedEntry.targetLang);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  }, [selectedEntry]);

  useEffect(() => {
    const delayDebounce = setTimeout(async () => {
      const trimmedQuery = query.trim().toLowerCase();
      if (trimmedQuery.length >= 2) {
        const localMatches = history
          .filter(e => e.sourceLang === sourceLang && e.term.toLowerCase().includes(trimmedQuery))
          .map(e => ({ term: e.term, source: 'local' as const }));

        const seedMatches = Object.values(SEED_ARCHIVE)
          .filter(e => e?.term && e.term.toLowerCase().includes(trimmedQuery))
          .map(e => ({ term: e!.term!, source: 'seed' as const }));

        let globalMatches: SuggestionItem[] = [];
        try {
          const globalTerms = await fetchSuggestions(query, sourceLang);
          globalMatches = globalTerms.map(term => ({ term, source: 'global' as const }));
        } catch (e) {
          console.warn("Global suggestions fetch failed");
        }

        const combined = [...localMatches, ...seedMatches, ...globalMatches];
        const unique = combined.filter((v, i, a) => 
          a.findIndex(t => t.term.toLowerCase() === v.term.toLowerCase()) === i
        ).slice(0, 8);

        setSuggestions(unique);
        setShowSuggestions(unique.length > 0);
        setSelectedIndex(-1);
      } else {
        setSuggestions([]);
        setShowSuggestions(false);
      }
    }, 250);
    return () => clearTimeout(delayDebounce);
  }, [query, sourceLang, history]);

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (suggestionRef.current && !suggestionRef.current.contains(e.target as Node)) {
        setShowSuggestions(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleSourceLangChange = useCallback(async (lang: Language) => {
    await resumeAudioContext();
    if (lang === targetLang) setTargetLang(sourceLang);
    setSourceLang(lang);
    triggerHaptic('light');
  }, [sourceLang, targetLang]);

  const handleTargetLangChange = useCallback(async (lang: Language) => {
    await resumeAudioContext();
    if (lang === sourceLang) setSourceLang(targetLang);
    setTargetLang(lang);
    triggerHaptic('light');
  }, [sourceLang, targetLang]);

  const localCache = useMemo(() => {
    const cache = new Map<string, LexicalEntry>();
    Object.entries(SEED_ARCHIVE).forEach(([key, entry]) => {
      const parts = key.split('-');
      const sL = parts[1] as Language;
      const tL = parts[2] as Language;
      if (entry.term) {
        const norm = normalize(entry.term, sL);
        cache.set(`${norm}-${sL}-${tL}`, { ...entry, id: `seed-${key}`, normalizedTerm: norm, sourceLang: sL, targetLang: tL } as any);
      }
    });
    history.forEach(entry => {
      const norm = normalize(entry.term, entry.sourceLang);
      cache.set(`${norm}-${entry.sourceLang}-${entry.targetLang}`, entry);
    });
    return cache;
  }, [history]);

  const handleSearch = async (overrideQuery?: string) => {
    const cleanQuery = (overrideQuery || query).trim();
    if (!cleanQuery) return;

    setSearchError(null);
    if (inputRef.current) inputRef.current.blur();

    // Resume audio context inside user-triggered handler for iOS compatibility
    try {
      await resumeAudioContext();
    } catch (e) {
      console.debug("Context resume bypassed");
    }

    setShowSuggestions(false);
    setQuery(cleanQuery);

    if (autoAudio) {
      speak(cleanQuery, sourceLang).catch(() => {});
    }

    const normQuery = normalize(cleanQuery, sourceLang);
    const cacheKey = `${normQuery}-${sourceLang}-${targetLang}`;

    const localHit = localCache.get(cacheKey);
    if (localHit) {
      setResult(localHit);
      if (autoAudio) {
        setTimeout(() => speak(localHit.mainTranslation, targetLang).catch(() => {}), 400);
      }
      return;
    }

    setLoading(true);
    setResult(null);

    try {
      const globalHit = await fetchGlobalEntry(normQuery, sourceLang, targetLang);
      if (globalHit) {
        setResult(globalHit);
        onEntrySaved(globalHit);
        setLoading(false);
        if (autoAudio) {
          setTimeout(() => speak(globalHit.mainTranslation, targetLang).catch(() => {}), 400);
        }
        return;
      }

      const finalEntry = await translateWord(cleanQuery, sourceLang, targetLang);
      finalEntry.normalizedTerm = normQuery;

      setResult(finalEntry);
      onEntrySaved(finalEntry);
      saveGlobalEntry(finalEntry);

      if (autoAudio) {
        setTimeout(() => speak(finalEntry.mainTranslation, targetLang).catch(() => {}), 400);
      }
    } catch (err) {
      console.error("Philologist Engine Error:", err);
      setSearchError("The archive is temporarily silent. Check your connection.");
      triggerHaptic('error');
    } finally {
      setLoading(false);
    }
  };

  const startVoiceSearch = async () => {
    if (isListening) return;
    setMicDenied(false);

    // iOS/Safari Optimization: Request permission once and store reference
    if (!activeMicStream) {
      try {
        activeMicStream = await navigator.mediaDevices.getUserMedia({ audio: true });
      } catch (err) {
        console.error("Linguistic access denied:", err);
        setMicDenied(true);
        triggerHaptic('error');
        return;
      }
    }

    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      alert("Linguistic transcription not supported in this vessel.");
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.lang = sourceLang === 'German' ? 'de-DE' : sourceLang === 'Russian' ? 'ru-RU' : sourceLang === 'Uzbek' ? 'uz-UZ' : 'en-US';
    recognition.interimResults = false;
    recognition.maxAlternatives = 1;

    recognition.onstart = () => {
      setIsListening(true);
      triggerHaptic('medium');
    };

    recognition.onresult = (event: any) => {
      const speechToText = event.results[0][0].transcript;
      setQuery(speechToText);
      handleSearch(speechToText);
    };

    recognition.onerror = (event: any) => {
      setIsListening(false);
      if (event.error === 'not-allowed') {
        setMicDenied(true);
        activeMicStream = null; 
      }
      if (event.error !== 'no-speech') triggerHaptic('error');
    };

    recognition.onend = () => {
      setIsListening(false);
    };

    try {
      recognition.start();
    } catch (e) {
      console.error("Failed to start speech recognition:", e);
      setIsListening(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      handleSearch();
    }
    if (!showSuggestions) return;

    if (e.key === 'ArrowDown') {
      e.preventDefault();
      setSelectedIndex(prev => (prev + 1) % suggestions.length);
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      setSelectedIndex(prev => (prev - 1 + suggestions.length) % suggestions.length);
    } else if (e.key === 'Enter' && selectedIndex >= 0) {
      e.preventDefault();
      const selected = suggestions[selectedIndex];
      setQuery(selected.term);
      handleSearch(selected.term);
    } else if (e.key === 'Escape') {
      setShowSuggestions(false);
    }
  };

  const swapLanguages = useCallback(async () => {
    try { await resumeAudioContext(); } catch(e){}
    setSourceLang(prevS => {
      const currentT = targetLang;
      setTargetLang(prevS);
      return currentT;
    });
    triggerHaptic('medium');
  }, [targetLang]);

  return (
    <div className="space-y-8 md:space-y-16 max-w-7xl mx-auto contain-layout">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-8 pt-4">
        <div className="flex items-center gap-6">
          <div className="space-y-1 border-l-2 border-[#7c1a1a] pl-4 block">
            <span className="text-[8px] uppercase tracking-[0.4em] text-stone-400 font-black">Philological Mastery</span>
            <div className="flex items-baseline gap-2">
              <span className="text-xl md:text-2xl font-black serif text-stone-900 leading-none">{profile.xp}</span>
              <span className="text-[7px] uppercase tracking-[0.2em] text-stone-300 font-bold">Total XP</span>
            </div>
          </div>
        </div>

        <div className="flex flex-col lg:flex-row items-center gap-6 lg:gap-12 w-full md:w-auto">
          <div className="flex flex-col sm:flex-row items-center gap-4 bg-stone-50 p-2 rounded-sm w-full sm:w-auto border border-stone-100 shadow-inner">
             <div className="grid grid-cols-4 bg-white shadow-sm overflow-hidden rounded-sm w-full sm:w-auto ring-1 ring-stone-100">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button key={full} type="button" onClick={() => handleSourceLangChange(full)}
                    className={`px-3 sm:px-5 py-2.5 text-[9px] font-black tracking-widest border-r border-stone-100 last:border-r-0 transition-all ${sourceLang === full ? 'bg-stone-900 text-white' : 'text-stone-300 hover:text-stone-600'}`}>
                    {short}
                  </button>
                ))}
             </div>
             <button type="button" onClick={swapLanguages} className="text-stone-300 hover:text-[#7c1a1a] transition-all p-2 hover:rotate-180 duration-500 transform sm:rotate-0 rotate-90 active:scale-90">
               <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="m17 2 4 4-4 4"/><path d="M3 11v-1a4 4 0 0 1 4-4h14"/><path d="m7 22-4-4 4-4"/><path d="M21 13v1a4 4 0 0 1-4 4H3"/></svg>
             </button>
             <div className="grid grid-cols-4 bg-white shadow-sm overflow-hidden rounded-sm w-full sm:w-auto ring-1 ring-stone-100">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button key={full} type="button" onClick={() => handleTargetLangChange(full)}
                    className={`px-3 sm:px-5 py-2.5 text-[9px] font-black tracking-widest border-r border-stone-100 last:border-r-0 transition-all ${targetLang === full ? 'bg-[#7c1a1a] text-white' : 'text-stone-300 hover:text-stone-600'}`}>
                    {short}
                  </button>
                ))}
             </div>
          </div>
          <div className="flex items-center gap-4 bg-stone-50/50 px-4 py-2 rounded-full border border-stone-100">
            <span className="text-[10px] uppercase tracking-[0.2em] text-stone-400 font-black">AUTO-PRONOUNCE</span>
            <button onClick={async () => { try { await resumeAudioContext(); } catch(e){} setAutoAudio(!autoAudio); triggerHaptic('light'); }} className={`w-10 h-5 rounded-full relative transition-all duration-300 p-1 ${autoAudio ? 'bg-[#7c1a1a]' : 'bg-stone-200'}`}>
              <div className={`w-3 h-3 bg-white rounded-full transition-all shadow-md ${autoAudio ? 'translate-x-5' : 'translate-x-0'}`} />
            </button>
          </div>
        </div>
      </div>

      <div className="relative w-full" ref={suggestionRef}>
        <form onSubmit={(e) => { e.preventDefault(); handleSearch(); }} className="relative z-20">
          <div className={`bg-white border border-stone-200 shadow-sm hover:border-[#7c1a1a]/50 focus-within:border-[#7c1a1a] focus-within:ring-8 focus-within:ring-[#7c1a1a]/5 transition-all group rounded-sm overflow-hidden flex items-stretch min-h-[70px] md:min-h-[120px] ${isListening ? 'ring-4 ring-[#7c1a1a]/20 animate-pulse' : ''}`}>
            <div className="flex-1 flex items-center px-6 md:px-12 relative">
              <input 
                ref={inputRef}
                type="text" 
                value={query} 
                onChange={(e) => setQuery(e.target.value)} 
                onFocus={async () => { try { await resumeAudioContext(); } catch(e){} if (suggestions.length > 0) setShowSuggestions(true); }}
                onKeyDown={handleKeyDown}
                placeholder={isListening ? "Listening..." : "Summon an inscription..."}
                className="w-full text-2xl md:text-6xl serif bg-transparent outline-none text-stone-900 placeholder:text-stone-100 lowercase font-medium tracking-tighter leading-none" 
              />
              <button 
                type="button" 
                onClick={startVoiceSearch}
                className={`ml-4 p-3 rounded-full transition-all ${isListening ? 'bg-[#7c1a1a] text-white scale-110 shadow-lg' : 'text-stone-500 hover:text-[#7c1a1a] hover:bg-stone-50'}`}
              >
                <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3.5" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2a3 3 0 0 0-3 3v7a3 3 0 0 0 6 0V5a3 3 0 0 0-3-3Z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" x2="12" y1="19" y2="22"/></svg>
              </button>
            </div>
            <button type="submit" disabled={loading} className="bg-stone-50 border-l border-stone-100 px-6 md:px-14 text-stone-600 hover:text-[#7c1a1a] hover:bg-white transition-all transform active:scale-95 flex items-center justify-center">
              {loading ? <div className="w-6 h-6 md:w-12 md:h-12 border-[4px] border-[#7c1a1a] border-t-transparent rounded-full animate-spin" /> : <svg xmlns="http://www.w3.org/2000/svg" className="w-6 h-6 md:w-16 md:h-16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="m12 5 7 7-7 7"/></svg>}
            </button>
          </div>
        </form>

        {searchError && (
          <p className="mt-4 text-red-600 text-[10px] uppercase tracking-widest font-black animate-in fade-in slide-in-from-top-1">
            {searchError}
          </p>
        )}

        {micDenied && (
          <div className="mt-4 p-4 bg-red-50 border border-red-100 rounded-sm">
            <p className="text-red-800 text-[10px] uppercase tracking-widest font-black">Microphone access denied. Please allow access in browser settings to use voice search.</p>
          </div>
        )}

        {showSuggestions && (
          <div className="absolute top-full left-0 right-0 bg-white border border-stone-200 shadow-2xl z-10 animate-in fade-in slide-in-from-top-2 duration-500 rounded-b-sm overflow-hidden max-h-[400px] overflow-y-auto">
             {suggestions.map((s, idx) => (
               <button 
                 key={idx} 
                 onClick={() => { setQuery(s.term); handleSearch(s.term); }}
                 onMouseEnter={() => setSelectedIndex(idx)}
                 className={`w-full text-left px-8 md:px-12 py-5 hover:bg-stone-50 border-b border-stone-50 last:border-0 flex items-center justify-between group transition-all ${selectedIndex === idx ? 'bg-stone-50 border-l-[4px] border-l-[#7c1a1a]' : 'border-l-[4px] border-l-transparent'}`}
               >
                 <div className="flex items-center gap-4">
                    <span className={`serif text-xl md:text-2xl transition-colors ${selectedIndex === idx ? 'text-stone-900' : 'text-stone-600'}`}>{s.term}</span>
                 </div>
                 <span className={`text-[8px] md:text-[9px] uppercase tracking-[0.3em] font-black px-3 py-1.5 rounded-sm border transition-all ${
                   s.source === 'local' ? 'bg-[#7c1a1a]/5 text-[#7c1a1a] border-[#7c1a1a]/10' : 
                   s.source === 'seed' ? 'bg-stone-100 text-stone-500 border-stone-200' : 
                   'bg-stone-900 text-white border-stone-900 shadow-sm'
                 }`}>
                   {s.source === 'local' ? 'Archive' : s.source === 'seed' ? 'Scribe' : 'Global'}
                 </span>
               </button>
             ))}
          </div>
        )}
      </div>

      <div className="min-h-[60px] will-change-contents">
        {loading && (
          <div className="bg-white border border-stone-100 p-12 md:p-24 animate-pulse flex flex-col items-center justify-center space-y-6">
            <div className="w-16 h-16 border-4 border-[#7c1a1a] border-t-transparent rounded-full animate-spin"></div>
            <p className="serif text-2xl italic text-stone-300">Consulting the Lexicon...</p>
          </div>
        )}
        {result && !loading && <ResultCard entry={result} onSearchTerm={(term) => handleSearch(term)} />}
        {!result && !loading && (
          <div className="py-20 text-center space-y-12">
            <div className="max-w-2xl mx-auto px-4">
              <h2 className="serif text-4xl md:text-6xl font-black text-stone-900 mb-6 lowercase tracking-tighter">Scholarly Discovery</h2>
              <p className="text-stone-400 serif italic text-xl md:text-2xl leading-relaxed">
                The engine awaits your command. Search for etymologies, or test your mastery in the <button onClick={onStartArena} className="text-[#7c1a1a] underline underline-offset-8 decoration-1 hover:decoration-2 transition-all">Scholarly Arena</button>.
              </p>
            </div>
          </div>
        )}
      </div>

      <div className="pt-16 md:pt-32 border-t border-stone-100">
        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-8 mb-12">
          <div className="border-l-[3px] border-[#7c1a1a] pl-6 md:pl-10 py-1">
            <h2 className="text-[12px] uppercase tracking-[0.5em] text-stone-900 font-black mb-1">Archival Chronicles</h2>
            <p className="text-stone-400 text-[9px] uppercase tracking-[0.2em] font-medium italic">Persistent insights</p>
          </div>
          <button 
            onClick={async () => { try { await resumeAudioContext(); } catch(e){} onStartArena(); }} 
            className="group relative bg-[#7c1a1a] text-white px-10 py-4 flex items-center gap-4 shadow-xl hover:shadow-[#7c1a1a]/30 hover:-translate-y-1 active:translate-y-0 transition-all rounded-sm w-full sm:w-auto justify-center"
          >
            <svg className="group-hover:rotate-45 transition-transform duration-500" xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="currentColor"><path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z"/></svg>
            <span className="text-[10px] uppercase tracking-[0.5em] font-black relative z-10">Start Arena</span>
          </button>
        </div>
        <HistoryGrid history={history} onEntryClick={onEntryClick} />
      </div>
    </div>
  );
};

export default Dictionary;
